    def _export_guard(audio):  # type: ignore[misc]
        audio = np.asarray(audio, dtype=np.float32)
        audio = np.nan_to_num(audio, nan=0.0, posinf=0.0, neginf=0.0)
        return np.clip(audio, -1.0, 1.0)

