# ── Quality Meter: circular arc gauge (MOS 0–5 → green/yellow/red) ──────────
class QualityMeterWidget(QWidget):
    """Horizontal VU-style quality bar displaying MOS quality (0–5 scale).

    Fills left→right with a red→yellow→green gradient.
    Always visible; shows placeholder text when not yet measured.
    """

    def __init__(self, parent=None) -> None:
        super().__init__(parent)
        self.setFixedHeight(22)
        self.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)
        self.setAccessibleName("Klangqualitätsanzeige")
        self.setAccessibleDescription("Zeigt Prognose, Live-Schätzung oder final gemessenen MOS-Wert an.")
        self._mos: float = 0.0
        self._max_mos: float = 5.0
        self._measurement_state: str = "Noch nicht gemessen"
        self._measurement_detail: str = ""
        self._refresh_tooltip()

    def _refresh_tooltip(self) -> None:
        """Aktualisiert den erklärenden Tooltip passend zum Messzustand."""
        tip = (
            "Klangqualitäts-Anzeige\n"
            f"Status: {self._measurement_state}\n"
            "1 = sehr schlecht · 2 = schlecht · 3 = akzeptabel · 4 = gut · 5 = exzellent"
        )
        if self._measurement_detail:
            tip += f"\n{self._measurement_detail}"
        self.setToolTip(tip)

    def set_measurement_state(self, state: str, detail: str = "") -> None:
        """Setzt sichtbar, ob der MOS Prognose, Live-Schätzung oder finale Messung ist."""
        self._measurement_state = str(state or "Noch nicht gemessen")
        self._measurement_detail = str(detail or "")
        self._refresh_tooltip()
        self.update()

    def set_mos(self, mos: float) -> None:
        """Aktualisiert meter to *mos* value (0–5) and repaint."""
        self._mos = float(max(0.0, min(self._max_mos, mos)))
        self.update()

    def reset(self) -> None:
        """Setzt zurück: meter to empty state."""
        self._mos = 0.0
        self.set_measurement_state("Noch nicht gemessen")
        self.update()

    def paintEvent(self, _event) -> None:
        """Render the current MOS bar and its scale markers."""
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)

        w, h = self.width(), self.height()
        m = 2

        # ── Container background ──────────────────────────────────────
        bg_rect = QRectF(m, m, w - 2 * m, h - 2 * m)
        p.setPen(QPen(QColor(50, 65, 100, 90), 1))
        p.setBrush(QBrush(QColor(16, 20, 38, 200)))
        p.drawRoundedRect(bg_rect, 3, 3)

        fraction = self._mos / self._max_mos  # 0.0–1.0

        # ── Gradient fill (left → right) ──────────────────────────────
        if fraction > 0.001:
            fill_w = (w - 2 * m) * fraction
            fill_rect = QRectF(m, m, fill_w, h - 2 * m)

            # Gradient spans full bar width so leading edge always shows color
            grad = QLinearGradient(m, 0, w - m, 0)
            grad.setColorAt(0.0, QColor(210, 55, 55, 210))
            grad.setColorAt(0.35, QColor(215, 175, 35, 210))
            grad.setColorAt(1.0, QColor(55, 195, 75, 210))

            clip_path = QPainterPath()
            clip_path.addRoundedRect(fill_rect, 3, 3)
            p.setClipPath(clip_path)
            p.fillRect(fill_rect, QBrush(grad))
            p.setClipping(False)

        # ── Tick marks at 1/5, 2/5, 3/5, 4/5 ────────────────────────
        p.setPen(QPen(QColor(40, 55, 90, 130), 1))
        inner_w = w - 2 * m
        for step in range(1, 5):
            tx = m + inner_w * step / 5
            p.drawLine(QPointF(tx, m + 2), QPointF(tx, h - m - 2))

        # ── Text overlay ──────────────────────────────────────────────
        font = p.font()
        font.setPointSize(7)
        if self._mos > 0.01:
            font.setBold(True)
            p.setFont(font)
            p.setPen(QPen(QColor(230, 235, 245)))
            p.drawText(bg_rect, Qt.AlignmentFlag.AlignCenter, f"{self._measurement_state}: {self._mos:.1f} / 5.0")
        else:
            font.setBold(False)
            p.setFont(font)
            p.setPen(QPen(QColor(75, 90, 115)))
            p.drawText(bg_rect, Qt.AlignmentFlag.AlignCenter, f"Klangqualität: {self._measurement_state}")

        p.end()


class _ElidingLabel(QLabel):
    """Single-line label that elides long text instead of visually colliding."""

    def __init__(self, text: str = "", parent=None) -> None:
        super().__init__("", parent)
        self._full_text = str(text or "")
        self._base_tooltip = ""
        self._apply_elided_text()

    def setBaseToolTip(self, text: str) -> None:
        """Store a non-elision tooltip prefix for later reuse."""
        self._base_tooltip = str(text or "")
        self._update_tooltip(is_elided=False)

    def setText(self, text: str) -> None:  # type: ignore[override]
        """Store new source text and refresh the elided display string."""
        self._full_text = str(text or "")
        self._apply_elided_text()

    def text(self) -> str:  # type: ignore[override]
        """Gibt the unelided source text zurück."""
        return self._full_text

    def resizeEvent(self, event) -> None:
        """Recompute elision whenever the available label width changes."""
        super().resizeEvent(event)
        self._apply_elided_text()

    def _apply_elided_text(self) -> None:
        _full = self._full_text
        _width = max(24, self.contentsRect().width() - 4)
        _fm = self.fontMetrics()
        _elided = _fm.elidedText(_full, Qt.TextElideMode.ElideRight, _width)
        QLabel.setText(self, _elided)
        self._update_tooltip(is_elided=_elided != _full)

    def _update_tooltip(self, is_elided: bool) -> None:
        if is_elided and self._full_text:
            if self._base_tooltip:
                QLabel.setToolTip(self, f"{self._base_tooltip}<br><br><small>{self._full_text}</small>")
            else:
                QLabel.setToolTip(self, self._full_text)
        else:
            QLabel.setToolTip(self, self._base_tooltip)


class _WrappingStatusLabel(QLabel):
    """Mehrzeiliges Statuslabel ohne Eliding fuer laufende Prozessdetails."""

    def __init__(self, text: str = "", parent=None) -> None:
        super().__init__(str(text or ""), parent)
        self._base_tooltip = ""
        self.setWordWrap(True)
        self.setTextInteractionFlags(Qt.TextInteractionFlag.TextSelectableByMouse)

    def setBaseToolTip(self, text: str) -> None:
        self._base_tooltip = str(text or "")
        QLabel.setToolTip(self, self._base_tooltip)


def _defect_analysis_to_display(scores: dict, status: str = "detected") -> dict:
    """Konvertiert DefectScanner.scan().scores (Dict[DefectType, DefectScore]) in Display-Dict.

    Skalierung Severity [0.0–1.0] → Widget-kompatible Typen:
        Integer-Felder (Zaehlwerte): clicks, crackle, pops, clipping, sibilance, dropout
        Float-Felder (physikalisch): hum [Hz], noise_level [dB], wow [%], flutter [%]
        Float-Felder (0–100 %): alle weiteren Defekttypen
    """
    DefectType = _bridge_get_defect_type()
    if DefectType is None:
        return {"status": status}

    def _sev(key) -> float:
        ds = scores.get(key)
        if ds is None:
            return 0.0
        return float(getattr(ds, "severity", 0.0) or 0.0)

    def _sev_opt(attr: str) -> float:
        dt = getattr(DefectType, attr, None)
        if dt is None:
            return 0.0
        return _sev(dt)

    sev_clicks = _sev(DefectType.CLICKS)
    sev_crackle = _sev(DefectType.CRACKLE)
    sev_clip = _sev(DefectType.CLIPPING)
    sev_hum = _sev(DefectType.HUM)
    sev_noise = _sev(DefectType.HIGH_FREQ_NOISE)
    sev_dropout = _sev(DefectType.DROPOUTS)
    sev_wow = _sev_opt("WOW")
    sev_flutter = _sev_opt("FLUTTER")
    sev_rumble = _sev(DefectType.LOW_FREQ_RUMBLE)
    sev_sibilance = _sev(DefectType.SIBILANCE)
    # Alle weiteren DefectTypes (mit _sev_opt für Rückwärtskompatibilität)
    sev_digital = _sev(DefectType.DIGITAL_ARTIFACTS)
    sev_compress = _sev(DefectType.COMPRESSION_ARTIFACTS)
    sev_stereo = _sev_opt("STEREO_IMBALANCE")
    sev_phase = _sev_opt("PHASE_ISSUES")
    sev_dc = _sev_opt("DC_OFFSET")
    sev_bw = _sev_opt("BANDWIDTH_LOSS")
    sev_pitch = _sev_opt("PITCH_DRIFT")
    sev_reverb = _sev_opt("REVERB_EXCESS")
    sev_print = _sev_opt("PRINT_THROUGH")
    sev_quant = _sev_opt("QUANTIZATION_NOISE")
    sev_jitter = _sev_opt("JITTER_ARTIFACTS")
    sev_dyncomp = _sev_opt("DYNAMIC_COMPRESSION_EXCESS")
    sev_pre_echo = _sev_opt("PRE_ECHO")
    sev_transient = _sev_opt("TRANSIENT_SMEARING")
    sev_soft_sat = _sev_opt("SOFT_SATURATION")
    sev_head = _sev_opt("HEAD_WEAR")
    sev_azimuth = _sev_opt("AZIMUTH_ERROR")
    sev_riaa = _sev_opt("RIAA_CURVE_ERROR")
    sev_alias = _sev_opt("ALIASING")
    sev_bias = _sev_opt("BIAS_ERROR")
    sev_amplitude_drift = _sev_opt("AMPLITUDE_DRIFT")
    sev_tape_head_level_dip = _sev_opt("TAPE_HEAD_LEVEL_DIP")
    sev_nr_breathing = _sev_opt("NR_BREATHING_ARTIFACT")
    sev_transport_bump = _sev_opt("TRANSPORT_BUMP")
    sev_vocal_harshness = _sev_opt("VOCAL_HARSHNESS")

    # Zeitpositionen (locations) pro Defekttyp für vertikale Marker in der Wellenform.
    # Format: {"clicks": [(t_start, t_end), ...], ...}
    def _locs(key) -> list:
        ds = scores.get(key)
        return list(ds.locations) if ds is not None and ds.locations else []

    def _locs_opt(attr: str) -> list:
        dt = getattr(DefectType, attr, None)
        if dt is None:
            return []
        return _locs(dt)

    def _ch_locs(key) -> dict:
        """Per-channel locations: {"L": [...], "R": [...]} if available."""
        ds = scores.get(key)
        if ds is None:
            return {}
        return dict(getattr(ds, "metadata", {}).get("channel_locations", {}))

    def _ch_locs_opt(attr: str) -> dict:
        dt = getattr(DefectType, attr, None)
        if dt is None:
            return {}
        return _ch_locs(dt)

    def _event_count(key, *meta_keys: str) -> int:
        """Authoritative event count: metadata total → len(locations) → 0."""
        ds = scores.get(key)
        if ds is None:
            return 0
        meta = getattr(ds, "metadata", {}) or {}
        for mk in meta_keys or ("total_clicks", "total_events", "total_count", "n_events"):
            if mk in meta:
                return int(meta[mk])
        return len(getattr(ds, "locations", []))

    def _event_count_opt(attr: str, *meta_keys: str) -> int:
        dt = getattr(DefectType, attr, None)
        if dt is None:
            return 0
        return _event_count(dt, *meta_keys)

    loc_sibilance = _locs(DefectType.SIBILANCE)
    loc_clipping = _locs(DefectType.CLIPPING)
    pops_events = _event_count(DefectType.CLIPPING, "total_events")

    return {
        # Integer-Felder → skalierte Zaehlwerte (Widget: animate_int + {:,} Formatierung)
        "clicks": int(sev_clicks * 500),
        "crackle": int(sev_crackle * 500),
        # Impulse must stay visible even at low clipping severity.
        # Prefer authoritative event metadata from DefectScanner.
        "pops": int(pops_events) if pops_events > 0 else int(sev_clip * 100),
        "clipping": int(sev_clip * 200),
        # Keep a minimum display count when temporal events exist; otherwise
        # valid low-severity sibilance segments become invisible after rounding.
        "sibilance": max(1, int(sev_sibilance * 300)) if loc_sibilance else int(sev_sibilance * 300),
        "dropout": int(sev_dropout * 50),
        # Float-Felder → physikalisch skaliert (Widget: animate_float)
        "hum": round(sev_hum * 50.0, 2),  # 0–50 Hz
        "noise_level": round(sev_noise * 75.0, 2),  # 0–75 dB Rauschboden
        "wow": round(sev_wow * 3.0, 3),  # 0–3 % Tonhöhenschwankung (< 0.5 Hz)
        "flutter": round(sev_flutter * 3.0, 3),  # 0–3 % Tonhöhenschwankung (0.5–200 Hz)
        # Float-Felder (0–100 % Schwere) für defect_summary_label
        "rumble": round(sev_rumble * 100.0, 2),
        "digital_artifacts": round(sev_digital * 100.0, 2),
        "compression_artifacts": round(sev_compress * 100.0, 2),
        "stereo_imbalance": round(sev_stereo * 100.0, 2),
        "phase_issues": round(sev_phase * 100.0, 2),
        "dc_offset": round(sev_dc * 100.0, 2),
        "bandwidth_loss": round(sev_bw * 100.0, 2),
        "pitch_drift": round(sev_pitch * 100.0, 2),
        "reverb_excess": round(sev_reverb * 100.0, 2),
        "print_through": round(sev_print * 100.0, 2),
        "quantization_noise": round(sev_quant * 100.0, 2),
        "jitter_artifacts": round(sev_jitter * 100.0, 2),
        "dynamic_compression_excess": round(sev_dyncomp * 100.0, 2),
        "pre_echo": round(sev_pre_echo * 100.0, 2),
        "transient_smearing": round(sev_transient * 100.0, 2),
        "soft_saturation": round(sev_soft_sat * 100.0, 2),
        "head_wear": round(sev_head * 100.0, 2),
        "azimuth_error": round(sev_azimuth * 100.0, 2),
        "head_misalignment": round(sev_azimuth * 100.0, 2),
        "riaa_curve_error": round(sev_riaa * 100.0, 2),
        "aliasing": round(sev_alias * 100.0, 2),
        "bias_error": round(sev_bias * 100.0, 2),
        "amplitude_drift": round(sev_amplitude_drift * 100.0, 2),
        "tape_head_level_dip": round(sev_tape_head_level_dip * 100.0, 2),
        "nr_breathing_artifact": round(sev_nr_breathing * 100.0, 2),
        "transport_bump": round(sev_transport_bump * 100.0, 2),
        "vocal_harshness": round(sev_vocal_harshness * 100.0, 2),
        # Zeitpositionen (Sekunden) für vertikale Wellenform-Marker
        "_locations": {
            "clicks": _locs(DefectType.CLICKS),
            "crackle": _locs(DefectType.CRACKLE),
            "pops": loc_clipping,  # same source as "clipping" (brief overload events)
            "clipping": loc_clipping,
            "hum": _locs(DefectType.HUM),
            "noise": _locs(DefectType.HIGH_FREQ_NOISE),
            "noise_level": _locs(DefectType.HIGH_FREQ_NOISE),  # alias so key always resolves
            "dropout": _locs(DefectType.DROPOUTS),
            "wow": _locs_opt("WOW"),
            "flutter": _locs_opt("FLUTTER"),
            "rumble": _locs(DefectType.LOW_FREQ_RUMBLE),
            "sibilance": loc_sibilance,
            "digital_artifacts": _locs(DefectType.DIGITAL_ARTIFACTS),
            "compression_artifacts": _locs(DefectType.COMPRESSION_ARTIFACTS),
            "stereo_imbalance": _locs_opt("STEREO_IMBALANCE"),
            "phase_issues": _locs_opt("PHASE_ISSUES"),
            "dc_offset": _locs_opt("DC_OFFSET"),
            "bandwidth_loss": _locs_opt("BANDWIDTH_LOSS"),
            "pitch_drift": _locs_opt("PITCH_DRIFT"),
            "reverb_excess": _locs_opt("REVERB_EXCESS"),
            "print_through": _locs_opt("PRINT_THROUGH"),
            "quantization_noise": _locs_opt("QUANTIZATION_NOISE"),
            "jitter_artifacts": _locs_opt("JITTER_ARTIFACTS"),
            "dynamic_compression_excess": _locs_opt("DYNAMIC_COMPRESSION_EXCESS"),
            "pre_echo": _locs_opt("PRE_ECHO"),
            "transient_smearing": _locs_opt("TRANSIENT_SMEARING"),
            "soft_saturation": _locs_opt("SOFT_SATURATION"),
            "head_wear": _locs_opt("HEAD_WEAR"),
            "azimuth_error": _locs_opt("AZIMUTH_ERROR"),
            "head_misalignment": _locs_opt("AZIMUTH_ERROR"),
            "riaa_curve_error": _locs_opt("RIAA_CURVE_ERROR"),
            "aliasing": _locs_opt("ALIASING"),
            "bias_error": _locs_opt("BIAS_ERROR"),
            "amplitude_drift": _locs_opt("AMPLITUDE_DRIFT"),
            "tape_head_level_dip": _locs_opt("TAPE_HEAD_LEVEL_DIP"),
            "nr_breathing_artifact": _locs_opt("NR_BREATHING_ARTIFACT"),
            "transport_bump": _locs_opt("TRANSPORT_BUMP"),
            "vocal_harshness": _locs_opt("VOCAL_HARSHNESS"),
        },
        # Authoritative event counts from scanner metadata (may exceed len(locations)).
        # Used by SongPrognoseWidget to display "× N" counts on chips.
        "_event_counts": {
            "clicks": _event_count(DefectType.CLICKS, "total_clicks"),
            "crackle": _event_count(DefectType.CRACKLE, "total_events"),
            "pops": _event_count(DefectType.CLIPPING, "total_events"),
            "clipping": _event_count(DefectType.CLIPPING, "total_events"),
            "sibilance": _event_count(DefectType.SIBILANCE, "total_events"),
            "dropout": _event_count(DefectType.DROPOUTS, "total_events"),
        },
        # Raw normalized severity (0.0–1.0) for pill severity colour (high/medium/low).
        "_severity_raw": {
            "clicks": sev_clicks,
            "crackle": sev_crackle,
            "pops": sev_clip,
            "clipping": sev_clip,
            "sibilance": sev_sibilance,
            "dropout": sev_dropout,
            "hum": sev_hum,
            "noise_level": sev_noise,
            "wow": sev_wow,
            "flutter": sev_flutter,
            "rumble": sev_rumble,
            "digital_artifacts": sev_digital,
            "compression_artifacts": sev_compress,
            "stereo_imbalance": sev_stereo,
            "phase_issues": sev_phase,
            "dc_offset": sev_dc,
            "bandwidth_loss": sev_bw,
            "pitch_drift": sev_pitch,
            "reverb_excess": sev_reverb,
            "print_through": sev_print,
            "quantization_noise": sev_quant,
            "jitter_artifacts": sev_jitter,
            "dynamic_compression_excess": sev_dyncomp,
            "pre_echo": sev_pre_echo,
            "transient_smearing": sev_transient,
            "soft_saturation": sev_soft_sat,
            "head_wear": sev_head,
            "azimuth_error": sev_azimuth,
            "head_misalignment": sev_azimuth,
            "riaa_curve_error": sev_riaa,
            "aliasing": sev_alias,
            "bias_error": sev_bias,
            "amplitude_drift": sev_amplitude_drift,
            "tape_head_level_dip": sev_tape_head_level_dip,
            "nr_breathing_artifact": sev_nr_breathing,
            "transport_bump": sev_transport_bump,
            "vocal_harshness": sev_vocal_harshness,
        },
        # Per-channel locations (L/R) for stereo channel-accurate overlay.
        # Premium: alle lokalisierbaren Impuls-/Event-Defekte kanalgenau,
        # kein "über einen Kamm" für L+R.
        "_channel_locations": {
            "clicks": _ch_locs(DefectType.CLICKS),
            "dropout": _ch_locs(DefectType.DROPOUTS),
            "crackle": _ch_locs(DefectType.CRACKLE),
            "clipping": _ch_locs(DefectType.CLIPPING),
            "sibilance": _ch_locs(DefectType.SIBILANCE),
            "amplitude_drift": _ch_locs_opt("AMPLITUDE_DRIFT"),
            "tape_head_level_dip": _ch_locs_opt("TAPE_HEAD_LEVEL_DIP"),
            "nr_breathing_artifact": _ch_locs_opt("NR_BREATHING_ARTIFACT"),
            "transport_bump": _ch_locs_opt("TRANSPORT_BUMP"),
        },
        "status": status,
    }


def _result_scores_to_display(defect_scores: dict, status: str = "completed") -> dict:
    """Konvertiert RestorationResult.defect_scores (Dict[DefectType, float]) in Display-Dict.

    defect_scores enthaelt Severity-Werte 0.0–1.0; Skalierung wie _defect_analysis_to_display.
    Nach Restaurierung liegen die Werte typisch nahe 0 → Zaehler gehen auf 0 zurueck.
    """
    DefectType = _bridge_get_defect_type()
    if DefectType is None:
        return {"status": status}

    def _f(key) -> float:
        v = defect_scores.get(key, 0.0)
        return float(v) if v is not None else 0.0

    def _f_opt(attr: str) -> float:
        dt = getattr(DefectType, attr, None)
        if dt is None:
            return 0.0
        return _f(dt)

    sev_clicks = _f(DefectType.CLICKS)
    sev_crackle = _f(DefectType.CRACKLE)
    sev_clip = _f(DefectType.CLIPPING)
    sev_hum = _f(DefectType.HUM)
    sev_noise = _f(DefectType.HIGH_FREQ_NOISE)
    sev_dropout = _f(DefectType.DROPOUTS)
    sev_wow = _f_opt("WOW")
    sev_flutter = _f_opt("FLUTTER")
    sev_rumble = _f(DefectType.LOW_FREQ_RUMBLE)
    sev_sibilance = _f(DefectType.SIBILANCE)
    sev_digital = _f(DefectType.DIGITAL_ARTIFACTS)
    sev_compress = _f(DefectType.COMPRESSION_ARTIFACTS)
    sev_stereo = _f_opt("STEREO_IMBALANCE")
    sev_phase = _f_opt("PHASE_ISSUES")
    sev_dc = _f_opt("DC_OFFSET")
    sev_bw = _f_opt("BANDWIDTH_LOSS")
    sev_pitch = _f_opt("PITCH_DRIFT")
    sev_reverb = _f_opt("REVERB_EXCESS")
    sev_print = _f_opt("PRINT_THROUGH")
    sev_quant = _f_opt("QUANTIZATION_NOISE")
    sev_jitter = _f_opt("JITTER_ARTIFACTS")
    sev_dyncomp = _f_opt("DYNAMIC_COMPRESSION_EXCESS")
    sev_pre_echo = _f_opt("PRE_ECHO")
    sev_transient = _f_opt("TRANSIENT_SMEARING")
    sev_soft_sat = _f_opt("SOFT_SATURATION")
    sev_head = _f_opt("HEAD_WEAR")
    sev_azimuth = _f_opt("AZIMUTH_ERROR")
    sev_riaa = _f_opt("RIAA_CURVE_ERROR")
    sev_alias = _f_opt("ALIASING")
    sev_bias = _f_opt("BIAS_ERROR")
    sev_amplitude_drift = _f_opt("AMPLITUDE_DRIFT")
    sev_tape_head_level_dip = _f_opt("TAPE_HEAD_LEVEL_DIP")
    sev_nr_breathing = _f_opt("NR_BREATHING_ARTIFACT")
    sev_transport_bump = _f_opt("TRANSPORT_BUMP")
    sev_vocal_harshness = _f_opt("VOCAL_HARSHNESS")

    return {
        "clicks": int(sev_clicks * 500),
        "crackle": int(sev_crackle * 500),
        "pops": int(sev_clip * 100),
        "clipping": int(sev_clip * 200),
        "sibilance": int(sev_sibilance * 300),
        "dropout": int(sev_dropout * 50),
        "hum": round(sev_hum * 50.0, 2),
        "noise_level": round(sev_noise * 75.0, 2),
        "wow": round(sev_wow * 3.0, 3),
        "flutter": round(sev_flutter * 3.0, 3),
        "rumble": round(sev_rumble * 100.0, 2),
        "digital_artifacts": round(sev_digital * 100.0, 2),
        "compression_artifacts": round(sev_compress * 100.0, 2),
        "stereo_imbalance": round(sev_stereo * 100.0, 2),
        "phase_issues": round(sev_phase * 100.0, 2),
        "dc_offset": round(sev_dc * 100.0, 2),
        "bandwidth_loss": round(sev_bw * 100.0, 2),
        "pitch_drift": round(sev_pitch * 100.0, 2),
        "reverb_excess": round(sev_reverb * 100.0, 2),
        "print_through": round(sev_print * 100.0, 2),
        "quantization_noise": round(sev_quant * 100.0, 2),
        "jitter_artifacts": round(sev_jitter * 100.0, 2),
        "dynamic_compression_excess": round(sev_dyncomp * 100.0, 2),
        "pre_echo": round(sev_pre_echo * 100.0, 2),
        "transient_smearing": round(sev_transient * 100.0, 2),
        "soft_saturation": round(sev_soft_sat * 100.0, 2),
        "head_wear": round(sev_head * 100.0, 2),
        "azimuth_error": round(sev_azimuth * 100.0, 2),
        "head_misalignment": round(sev_azimuth * 100.0, 2),
        "riaa_curve_error": round(sev_riaa * 100.0, 2),
        "aliasing": round(sev_alias * 100.0, 2),
        "bias_error": round(sev_bias * 100.0, 2),
        "amplitude_drift": round(sev_amplitude_drift * 100.0, 2),
        "tape_head_level_dip": round(sev_tape_head_level_dip * 100.0, 2),
        "nr_breathing_artifact": round(sev_nr_breathing * 100.0, 2),
        "transport_bump": round(sev_transport_bump * 100.0, 2),
        "vocal_harshness": round(sev_vocal_harshness * 100.0, 2),
        "_locations": {},  # Nach Restaurierung keine Zeitpositionen verfügbar
        "status": status,
    }


