        self._in_tick_heartbeat: bool = False  # W0201 §11 — Reentrancy-Guard _tick_heartbeat()
        self._progress_log_state: dict[str, Any] = {}  # W0201 §11 — Batch-Fortschritts-Log-State
        self._in_update_phase: bool = False  # W0201 §11 — Reentrancy-Guard _update_phase()
        self._phase_heartbeat_refresh_pending: bool = False  # W0201 §11 — Heartbeat-Refresh-Pending

        self.setWindowTitle(f"AURIK Professional v{_AURIK_VERSION}")

        # Window flags for frameless
        self.setWindowFlags(Qt.WindowType.FramelessWindowHint | Qt.WindowType.WindowSystemMenuHint)

        # App icon (title bar, taskbar, alt-tab)
        _res = Path(__file__).parent.parent / "resources"
        for _icon_path in (_res / "vinyl_gold.png", _res / "icon_premium.svg", _res / "icon.png"):
            if _icon_path.exists():
                self.setWindowIcon(QIcon(str(_icon_path)))
                break

        # Linux compositors may show holes with translucent frameless windows.
        if sys.platform.startswith("linux"):
            self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground, False)
        else:
            self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground, True)

        # Window properties
        self._ui_font_family = self._setup_app_fonts()
        screen = QApplication.primaryScreen()
        self._ui_scale = self._compute_ui_scale(screen)
        if screen is not None:
            available = screen.availableGeometry()
            min_w = min(1280, max(960, available.width() - 40))
            min_h = min(900, max(640, available.height() - 40))
            self.setMinimumSize(min_w, min_h)
            self.resize(min(1500, available.width() - 20), min(1000, available.height() - 20))
        else:
            self.setMinimumSize(1280, 900)
            self.resize(1500, 1000)

        # State
        self.is_maximized = False
        self.old_position = None

        # Processing state
        self.current_file = None
        self.current_file_path = None
        self.processing_thread = None
        self.batch_thread = None
        self.batch_queue = SimpleBatchQueue()
        self._processing_transition = False
