    def _apply_theme(self):
        """Wendet dunkles Premium-Theme für zweispaltiges Layout an."""
        main_bg = "#080a18" if sys.platform.startswith("linux") else "transparent"
        font_family = getattr(self, "_ui_font_family", "Sans Serif")
        base_pt = self._pt(9.2)
        self.setStyleSheet(
            "QMainWindow {"
            f"background: {main_bg};"
            "}"
            "QWidget#mainContainer {"
            "background: #080a18;"
            "border-radius: 15px;"
            "}"
            "QWidget#bodyWidget {"
            "background: transparent;"
            "}"
            "QWidget#mainArea {"
            "background: transparent;"
            "}"
            "QWidget {"
            f"font-family: '{font_family}';"
            f"font-size: {base_pt:.1f}pt;"
            "}"
            "QLabel {"
            "color: #F3F6FF;"
            "}"
            "QSplitter::handle {"
            "background: rgba(255, 255, 255, 0.1);"
            "width: 2px;"
            "}"
        )

    def _center_window(self):
        """Center window on screen"""
        _screen = QApplication.primaryScreen()
        if _screen is None:
            return
        screen = _screen.availableGeometry()
        size = self.frameGeometry()
        x = screen.x() + max(0, (screen.width() - size.width()) // 2)
        y = screen.y() + max(0, (screen.height() - size.height()) // 2)
        self.move(x, y)

    def _animate_fade_in(self):
        """Animate window fade-in"""
        self.setWindowOpacity(0)
        self.animation = QPropertyAnimation(self, b"windowOpacity")
        self.animation.setDuration(500)
        self.animation.setStartValue(0)
        self.animation.setEndValue(1)
        self.animation.setEasingCurve(QEasingCurve.Type.OutCubic)
        self.animation.start()

    def _setup_shortcuts(self):
        """Keyboard-Shortcuts gemäß §11.4 der copilot-instructions (bindend).

        Tabelle:
            Leertaste   → Play / Pause
            A           → Original hören
            B           → Restauriert hören
            Ctrl+O      → Datei öffnen
            Ctrl+S      → Exportieren
            Ctrl+R      → RESTORATION starten
            Ctrl+Shift+R → STUDIO_2026 starten
            Escape      → Restaurierung stoppen
            Ctrl+Z      → Letzten Export-Pfad in Zwischenablage
        """
        self._shortcuts = []

        def _bind_shortcut(seq, handler) -> None:
            sc = QShortcut(QKeySequence(seq), self)
            sc.activated.connect(handler)
            self._shortcuts.append(sc)

        _bind_shortcut(Qt.Key.Key_Space, self._toggle_playback)
        _bind_shortcut(
            Qt.Key.Key_A,
            lambda: (
                self._ab_switch_source("original")
                if getattr(getattr(self, "btn_ab_sync", None), "isChecked", lambda: False)()
                else (self._play_audio(self._orig_audio, self._orig_sr) if self._orig_audio is not None else None)
            ),
        )
        _bind_shortcut(
            Qt.Key.Key_B,
            lambda: (
                self._ab_switch_source("restored")
                if getattr(getattr(self, "btn_ab_sync", None), "isChecked", lambda: False)()
                else (self._play_audio(self._rest_audio, self._rest_sr) if self._rest_audio is not None else None)
            ),
        )
        _bind_shortcut(QKeySequence.StandardKey.Open, self._open_file)
        _bind_shortcut(QKeySequence.StandardKey.Save, self._export_all)
        _bind_shortcut("Ctrl+R", lambda: self._process_with_mode("RESTORATION"))
        _bind_shortcut("Ctrl+Shift+R", lambda: self._process_with_mode("STUDIO_2026"))
        _bind_shortcut(Qt.Key.Key_Escape, self._cancel_processing)
        _bind_shortcut("Ctrl+Z", self._copy_last_output_to_clipboard)
        # L-Shortcut: Lyrics-Timeline-Overlay an/aus (§11.4 Spec 08)
        _bind_shortcut(Qt.Key.Key_L, self._toggle_lyrics_overlay)
        # F1: Shortcut-Übersicht
        _bind_shortcut(Qt.Key.Key_F1, self._show_shortcut_help)

        # F1 Help System — dedicated help search shortcut
        QtWidgets.QShortcut(QtGui.QKeySequence("F1"), self).activated.connect(self._show_help)

    # ── System Tray + Notifications ──────────────────────────────────────────

    def _setup_system_tray(self) -> None:
        """Erstellt system tray icon with context menu for background notifications."""
        if not QSystemTrayIcon.isSystemTrayAvailable():
            self._tray_icon = None
            return

        _res = Path(__file__).parent.parent / "resources"
        _icon = self.windowIcon()
        for _icon_path in (_res / "vinyl_gold.png", _res / "icon_premium.svg", _res / "icon.png"):
            if _icon_path.exists():
                _icon = QIcon(str(_icon_path))
                break

        self._tray_icon = QSystemTrayIcon(_icon, self)
        self._tray_icon.setToolTip("AURIK Professional")

        tray_menu = QMenu()
        tray_menu.setStyleSheet(
            "QMenu { background: #0d0d1f; color: #d0d8ff; border: 1px solid rgba(102,126,234,0.5);"
            " border-radius: 6px; padding: 4px; }"
            " QMenu::item { padding: 6px 18px; border-radius: 4px; }"
            " QMenu::item:selected { background: rgba(102,126,234,0.35); }"
        )
        _show_action = QAction("Aurik anzeigen", self)
        _show_action.triggered.connect(self._tray_show_window)
        tray_menu.addAction(_show_action)
        tray_menu.addSeparator()
        _quit_action = QAction("Beenden", self)
        _quit_action.triggered.connect(self.close)
        tray_menu.addAction(_quit_action)

        self._tray_icon.setContextMenu(tray_menu)
        self._tray_icon.activated.connect(self._on_tray_activated)
        self._tray_icon.show()

    def _tray_show_window(self) -> None:
        """Restauriert and raise window from tray."""
        self.showNormal()
        self.raise_()
        self.activateWindow()

    def _on_tray_activated(self, reason) -> None:
        """Verarbeitet tray icon click (double-click or trigger)."""
        if reason in (QSystemTrayIcon.ActivationReason.DoubleClick, QSystemTrayIcon.ActivationReason.Trigger):
            self._tray_show_window()

    def _tray_notify(self, title: str, message: str, icon=None) -> None:
        """Zeigt an: a desktop notification via the system tray icon."""
        _tray = getattr(self, "_tray_icon", None)
        if _tray is None or not _tray.isVisible():
            return
        _msg_icon = icon or QSystemTrayIcon.MessageIcon.Information
        _tray.showMessage(title, message, _msg_icon, 5000)

    # ── Recent Files Menu ────────────────────────────────────────────────────

    def _refresh_recent_files_menu(self) -> None:
        """Rebuild the recent files dropdown from QSettings."""
        _menu = getattr(self.title_bar, "_recent_menu", None) if hasattr(self, "title_bar") else None
        if _menu is None:
            return
        _menu.clear()
        _sm = getattr(self, "_settings", None)
        if _sm is None:
            return
        _files = _sm.recent_files()
        if not _files:
            _empty = QAction(t("ui.no_recent_files"), self)
            _empty.setEnabled(False)
            _menu.addAction(_empty)
            return
        for path in _files:
            _name = Path(path).name
            _dir = str(Path(path).parent)
            if len(_dir) > 40:
                _dir = "…" + _dir[-37:]
            _action = QAction(f"{_name}  ·  {_dir}", self)
            _p = str(path)  # capture for lambda
            _action.triggered.connect(lambda _checked, p=_p: self._load_file(p))
            _menu.addAction(_action)
        _menu.addSeparator()
        _clear = QAction("Liste leeren", self)
        _clear.triggered.connect(self._clear_recent_files)
        _menu.addAction(_clear)

    def _clear_recent_files(self) -> None:
        """Löscht the recent files list."""
        _sm = getattr(self, "_settings", None)
        if _sm is not None:
            _sm.clear_recent_files()
        self._refresh_recent_files_menu()

    def _toggle_playback(self):
        """Leertaste: Play/Pause — Wiedergabe stoppen oder Original starten."""
        if not _SD_AVAILABLE:
            return
        # ── Streaming-Player: Zustand direkt abfragen ─────────────────────────
        _sp = self._streaming_player
        if _sp is not None and _sp.available and _sp.is_playing:
            _sp.stop()
            return
        # ── Legacy sd.play() Pfad ──────────────────────────────────────────────
        if self._play_thread is not None and self._play_thread.is_alive():
            try:
                if not hasattr(self, "_sd_lock"):
                    self._sd_lock = threading.Lock()
                with self._sd_lock:
                    self._stop_sd_playback_locked()
            except Exception as exc:
                logger.warning("A/B playback toggle stop failed: %s", exc)
                if hasattr(self, "status_text"):
                    self._apply_status_text_style("error")
                    self.status_text.setText(t("status.playback_stop_failed"))
            return
        if self._orig_audio is not None:
            self._play_audio(self._orig_audio, self._orig_sr)

    def _show_help_menu(self) -> None:
        """Zeigt an: a help popup menu at the ? button position."""
        _menu = QMenu(self)
        _menu.setStyleSheet(
            "QMenu { background: #0d0d1f; color: #d0d8ff; border: 1px solid rgba(102,126,234,0.5);"
            " border-radius: 6px; padding: 4px; font-size: 10pt; }"
            " QMenu::item { padding: 8px 20px; border-radius: 4px; }"
            " QMenu::item:selected { background: rgba(102,126,234,0.35); }"
            " QMenu::separator { height: 1px; background: rgba(102,126,234,0.3); margin: 4px 8px; }"
        )

        _sc = QAction("⌨  Tastenkürzel  (F1)", self)
        _sc.triggered.connect(self._show_shortcut_help)
        _menu.addAction(_sc)

        _menu.addSeparator()

        _ug = QAction("📖  Benutzerhandbuch", self)
        _ug.triggered.connect(lambda: self._open_doc("USER_GUIDE.md"))
        _menu.addAction(_ug)

        _ts = QAction("🔧  Fehlerbehebung", self)
        _ts.triggered.connect(lambda: self._open_doc("TROUBLESHOOTING.md"))
        _menu.addAction(_ts)

        _cfg = QAction("⚙  Konfiguration", self)
        _cfg.triggered.connect(lambda: self._open_doc("CONFIGURATION.md"))
        _menu.addAction(_cfg)

        _menu.addSeparator()

        _sys = QAction("✓  Systemcheck", self)
        _sys.triggered.connect(self._show_system_check_dialog)
        _menu.addAction(_sys)

        _menu.addSeparator()

        _about = QAction(f"ℹ  Über Aurik  (v{_AURIK_VERSION})", self)
        _about.triggered.connect(self._show_about_dialog)
        _menu.addAction(_about)

        _menu.addSeparator()

        _update = QAction(t("help.check_update"), self)
        _update.triggered.connect(self._check_for_update_manual)
        _menu.addAction(_update)

        # Position at the ? button
        _btn = getattr(self.title_bar, "btn_help", None)
        if _btn is not None:
            _pos = _btn.mapToGlobal(_btn.rect().bottomLeft())
            _menu.exec_(_pos)
        else:
            _menu.exec_(self.mapToGlobal(self.rect().topRight()))

    def _open_doc(self, filename: str) -> None:
        """Öffnet a documentation file from docs/guides/ in the default application."""
        _base = Path(__file__).parent.parent.parent / "docs" / "guides" / filename
        if not _base.exists():
            # Fallback: try docs/ directly
            _base = Path(__file__).parent.parent.parent / "docs" / filename
        if _base.exists():
            try:
                if sys.platform.startswith("linux"):
                    subprocess.run(["xdg-open", str(_base)], check=False)
                elif sys.platform == "darwin":
                    subprocess.run(["open", str(_base)], check=False)
                else:
                    _open_with_system_default(str(_base))
            except Exception as exc:
                logger.warning("Failed to open doc %s: %s", filename, exc)
                self.status_text.setText(t("status.help_open_failed", file=filename))
        else:
            self.status_text.setText(t("status.help_not_found", file=filename))

