    def _request_processing_stop(self, reason: str, timeout_s: float = 5.0) -> bool:
        """Request async stop of active worker threads without blocking UI thread."""
        _bt = getattr(self, "batch_thread", None)
        _rft = getattr(self, "_ml_refinement_thread", None)
        _active = bool((_bt is not None and _bt.isRunning()) or (_rft is not None and _rft.isRunning()))
        if not _active:
            self._processing_transition = False
            return False
        if self._processing_transition:
            return True

        self._processing_transition = True
        self._stop_reason = reason
        self._stop_deadline = time.monotonic() + max(1.0, float(timeout_s))

        if self._watchdog_timer is not None and self._watchdog_timer.isActive():
            self._watchdog_timer.stop()

        try:
            if _bt is not None and _bt.isRunning():
                _bt.requestInterruption()
        except Exception:
            logger.exception("Failed to request interruption on batch thread")

        try:
            if _rft is not None and _rft.isRunning():
                _rft.requestInterruption()
        except Exception:
            logger.exception("Failed to request interruption on refinement thread")

        if self._stop_poll_timer is None:
            self._stop_poll_timer = QTimer(self)
            self._stop_poll_timer.setInterval(120)
            self._stop_poll_timer.timeout.connect(self._poll_processing_stop)
        if not self._stop_poll_timer.isActive():
            self._stop_poll_timer.start()

        self.title_bar.set_status(t("status.stopping_safely"), "#B8A068")
        self._apply_status_text_style("warning")
        self.status_text.setText(t("status.stopping_processing"))
        return True

    def _poll_processing_stop(self) -> None:
        """Poll stop progress; force-terminate only after timeout."""
        _bt = getattr(self, "batch_thread", None)
        _rft = getattr(self, "_ml_refinement_thread", None)
        _bt_running = bool(_bt is not None and _bt.isRunning())
        _rft_running = bool(_rft is not None and _rft.isRunning())

        if not _bt_running and not _rft_running:
            if self._stop_poll_timer is not None and self._stop_poll_timer.isActive():
                self._stop_poll_timer.stop()
            self._processing_transition = False
            self._ml_refinement_thread = None
            # KMV-Queue leeren: ein Abbruch betrifft alle pending Jobs (§2.38)
            self._kmv_pending_jobs.clear()
            if hasattr(self, "refinement_progress_bar"):
                self.refinement_progress_bar.setVisible(False)
            if self._heartbeat_timer is not None and self._heartbeat_timer.isActive():
                self._heartbeat_timer.stop()
            self._uv3 = {"active": False, "count": 0, "idx": 0, "started_at": 0.0, "pct": 0.0}  # §K
            # GIL-Switch-Intervall auf Normalwert zurücksetzen
            _prev = getattr(self, "_prev_switchinterval", 0.005)
            sys.setswitchinterval(_prev)
            self._set_left_panel_processing_focus(False)
            self._set_magic_buttons_enabled(True)
            self.progress_bar.setVisible(False)
            self.title_bar.set_status(t("status.cancelled"), "#B87A7A")
            self._apply_status_text_style("error")
            self.status_text.setText(t("status.processing_cancelled"))
            if self._pending_close_after_stop and not self._closing_in_progress:
                self._pending_close_after_stop = False
                self._closing_in_progress = True
                QTimer.singleShot(0, self.close)
            return

        if time.monotonic() < self._stop_deadline:
            return

        # Last resort after timeout — terminate() is a forceful OS-level kill;
        # wait() is intentionally skipped to avoid blocking the UI thread.
        # The next poll cycle will confirm isRunning() == False.
        try:
            if _bt is not None and _bt.isRunning():
                _bt.terminate()
        except Exception:
            logger.exception("Failed to force-terminate batch thread")
        try:
            if _rft is not None and _rft.isRunning():
                _rft.terminate()
        except Exception:
            logger.exception("Failed to force-terminate refinement thread")

        # Push deadline forward briefly to allow one more poll cycle.
        self._stop_deadline = time.monotonic() + 0.5

    def _cancel_processing(self):
        """Escape: Laufende Restaurierung sicher stoppen."""
        if not self._allow_action("cancel_processing", cooldown_ms=200):
            return
        self._request_processing_stop("user_cancel", timeout_s=6.0)

    def _copy_last_output_to_clipboard(self):
        """Ctrl+Z: Letzten Export-Pfad in die Zwischenablage kopieren."""
        last_output = None
        for item in reversed(self.batch_queue.items):
            if item.status == "completed" and item.output_file:
                last_output = item.output_file
                break
        if last_output:
            _clipboard = QApplication.clipboard()
            if _clipboard is not None:
                _clipboard.setText(str(last_output))
            self.status_text.setText(t("status.path_copied", file=Path(last_output).name))
        else:
            self.status_text.setText(t("status.no_export_path"))

    def _toggle_maximize(self):
        """Toggle window maximize/restore"""
        if self.is_maximized:
            self.showNormal()
            self.title_bar.is_maximized = False
            self.is_maximized = False
        else:
            self.showMaximized()
            self.title_bar.is_maximized = True
            self.is_maximized = True

    # Action Methods
    def dragEnterEvent(self, event):
        """Drag & Drop: Datei-Drop auf das Fenster akzeptieren."""
        if event.mimeData().hasUrls():
            urls = event.mimeData().urls()
            audio_exts = {".wav", ".mp3", ".flac", ".ogg", ".aiff", ".aif", ".m4a", ".wma"}
            if any(Path(u.toLocalFile()).suffix.lower() in audio_exts for u in urls):
                event.acceptProposedAction()
                # Prominentes Drop-Ziel: gesamter Visualisierungsbereich leuchtet auf
                self.detected_medium_label.setStyleSheet("""
                    color: #8fa4e8; font-size: 12pt; font-weight: bold; padding: 15px;
                    background: rgba(102, 126, 234, 0.18);
                    border-radius: 12px;
                    border: 3px dashed rgba(102, 126, 234, 0.85);
                """)
                self.detected_medium_label.setText(t("status.drop_release_to_load"))
                # Waveform-Bereich ebenfalls hervorheben
                if hasattr(self, "waveform_widget"):
                    self.waveform_widget.setStyleSheet("border: 3px dashed rgba(76,175,80,0.85); border-radius: 12px;")
                return
        event.ignore()

    def dragLeaveEvent(self, _event):
        """Drag & Drop: Rahmen zurücksetzen wenn Datei das Fenster verlässt."""
        # Nur zurücksetzen wenn keine Datei geladen ist — sonst bleibt die erkannte
        # Carrier-Info sichtbar (dragEnterEvent hatte sie temporär überschrieben).
        if not getattr(self, "current_file_path", None):
            self.detected_medium_label.setText("")
            self.detected_medium_label.setStyleSheet("""
                color: #7B93B8; font-size: 11pt; padding: 15px;
                background: rgba(102, 126, 234, 0.10);
                border-radius: 10px;
                border: 2px solid rgba(102, 126, 234, 0.22);
            """)
        if hasattr(self, "waveform_widget"):
            self.waveform_widget.setStyleSheet("")

    def dropEvent(self, event):
        """Drag & Drop: Abgelegte Audiodatei(en) laden."""
        audio_exts = {".wav", ".mp3", ".flac", ".ogg", ".aiff", ".aif", ".m4a", ".wma"}
        paths = [
            Path(u.toLocalFile()) for u in event.mimeData().urls() if Path(u.toLocalFile()).suffix.lower() in audio_exts
        ]
        if paths:
            self._load_file(str(paths[0]))
            for p in paths[1:]:
                self._add_to_queue(str(p))
        self.dragLeaveEvent(event)  # Rahmen zurücksetzen (inkl. waveform_widget)

    def _load_file(self, file_path: str):
        """Datei nicht-blockierend laden: sf.read + Carrier-Forensics im Hintergrundthread."""
        _prev_file_path = str(getattr(self, "current_file_path", "") or "")
        if _prev_file_path and _prev_file_path != str(file_path):
            # Harte Import-Grenze: Voranalyse-Caches der vorherigen Datei verwerfen,
            # damit beim nächsten Import niemals alte Ergebnisse weitergereicht werden.
            _bridge_clear_defect_cache(_prev_file_path)
            _bridge_clear_era_genre_cache(_prev_file_path)
            _bridge_clear_medium_cache(_prev_file_path)

        self.current_file_path = file_path
        self._file_load_token += 1
        # Track in recent files
        _sm = getattr(self, "_settings", None)
        if _sm is not None:
            _sm.add_recent_file(file_path)
            self._refresh_recent_files_menu()
        _load_token = int(self._file_load_token)

        # Cache-Invalidierung: veralteter DefectScan für diese Datei entfernen (§9.4).
        # Nötig wenn dieselbe Datei nach einer Änderung erneut geöffnet wird.
        _bridge_clear_defect_cache(file_path)
        _bridge_clear_era_genre_cache(file_path)
        _bridge_clear_medium_cache(file_path)
        # In-Memory-Handover ebenfalls zurücksetzen (kein Stale-Result in Queue-Settings).
        self._latest_pre_analysis_result = None
        self._latest_pre_analysis_file = ""
        # Lyrics-Overlay-Zustand zurücksetzen (neue Datei → kein altes Transkript)
        self._lyrics_overlay_visible = False
        self._lyrics_overlay_request_id += 1
        self._carrier_bg_label = t("status.analyzing_wait")
        self._carrier_bg_score = 0
        self._raw_medium_type = "unknown"
        self._era_genre_badge = ""
        self._era_genre_cached = ""  # Plain-text genre for era badge recombination (Bug-Fix: HTML-Split)
        # Chips in der Audio-Info-Bar beim neuen File zurücksetzen
        for _chip_attr in ("chip_era", "chip_genre", "chip_medium"):
            _chip = getattr(self, _chip_attr, None)
            if _chip is not None:
                _chip.setVisible(False)
                _chip.setText("")
        if hasattr(self, "_audio_info_bar"):
            self._audio_info_bar.setVisible(False)
        if hasattr(self, "waveform_widget"):
            self.waveform_widget.set_lyrics_transcription(None)

        # Sofortiges visuelles Feedback im Haupt-Thread (BEVOR der Hintergrundthread startet)
        self.status_text.setText(t("status.loading_file", file=Path(file_path).name))
        self._apply_status_text_style("warning")
        self._is_file_loading = True  # progress-bar zeigt Lade-%, nicht Scan-%
        if hasattr(self, "waveform_widget"):
            self.waveform_widget.is_loading = True
            self.waveform_widget.audio_data = None  # Drop-Overlay ersetzt durch Lade-Overlay
            self.waveform_widget.update()

        # Buttons sofort deaktivieren – bleiben disabled, bis Defektanalyse fertig ist
        for _btn_name in ("btn_magic_restoration", "btn_magic_studio"):
            if hasattr(self, _btn_name):
                _btn = getattr(self, _btn_name)
                _btn.setEnabled(False)
                _btn.update()
        if hasattr(self, "progress_bar"):
            self.progress_bar.setRange(0, 10000)
            self.progress_bar.setValue(0)
            self.progress_bar.setFormat(t("progress.loading_file"))
            self.progress_bar.setVisible(True)

        # Restaurierbarkeits-Banner zurücksetzen (neues File) – vor Thread-Start
        if hasattr(self, "restorability_banner"):
            self.restorability_banner.setText(t("ui.analyzing_wait_short"))
            self.restorability_banner.setStyleSheet("""
                color: #6080A0; font-size: 8pt; padding: 5px 8px;
                background: rgba(70, 90, 130, 0.08);
                border-radius: 8px; border: 1px solid rgba(70, 90, 130, 0.15);
            """)
            self.restorability_banner.setVisible(True)
        self._restorability_score = 50.0
        self._defect_scan_scores = {}  # Reset on new file — prevents stale scores from previous file
        self._preanalysis_flags: set[str] = set()  # "defect_scan" | "era_genre" | "carrier" added when done
        self._preanalysis_timeout_fired = False  # True when 15 s fallback fires
        self._preanalysis_finalized_for = ""  # file_path when finalized (double-fire guard)
        self._last_scan_pct_int: int = -1  # throttle: only update status_text when integer % changes
        self._recommended_mode = "RESTORATION"
        if hasattr(self, "mode_recommendation_label"):
            self.mode_recommendation_label.setText("—")
            self._set_info_card_state(self.mode_recommendation_label, "neutral", animate=False)
        self._apply_mode_recommendation_visuals()
        # Prognose-Widget zurücksetzen (neue Datei)
        if getattr(self, "prognose_widget", None) is not None:
            self.prognose_widget.reset()  # type: ignore[union-attr]

        # ── Animations-Timer-Cleanup bei Datei-Wechsel ───────────────────────
        # Laufende Animations-Timer vom vorherigen File stoppen, damit keine
        # veralteten Werte (altes Scan-Ergebnis) in die neue Anzeige durchsickern.
        _dt = getattr(self, "_defect_anim_timer", None)
        if _dt is not None and _dt.isActive():
            _dt.stop()
        # Stale animation state löschen — neue Datei beginnt sauber
        self.__dict__.pop("_defect_anim_target", None)
        self.__dict__.pop("_defect_initial_scores", None)
        self.__dict__.pop("_defect_initial_event_counts", None)
        self.__dict__.pop("_defect_remaining_event_counts", None)
        _mt = getattr(self, "_mos_anim_timer", None)
        if _mt is not None and _mt.isActive():
            _mt.stop()
        self._last_mos_displayed = 1.0  # MOS-Ausgangswert für neue Datei zurücksetzen

        # ── PFLICHT-GATE §10.5: AudioFileValidator vor dem Laden ─────────────
        # Zugriff ausschließlich über Bridge (§11.4 — kein direkter core/-Import)
        try:
            _validator = _bridge_get_audio_file_validator()
            if _validator is None:
                raise RuntimeError(
                    "Backend-Bridge nicht verfügbar. Datei-Validierung ohne Bridge ist im Frontend deaktiviert."
                )
            _val_result = _validator.validate(Path(file_path))
            _warnings = getattr(_val_result, "warnings", []) or []
            if _warnings:
                for _w in _warnings:
                    logger.warning("AudioFileValidator: %s", _w)
        except Exception as _val_exc:
            # Nutzer-sichtbare Fehlermeldung auf Deutsch (AudioLoadError hat .message_user)
            _user_msg = getattr(_val_exc, "message_user", str(_val_exc))
            for _btn_name in ("btn_magic_restoration", "btn_magic_studio"):
                if hasattr(self, _btn_name):
                    getattr(self, _btn_name).setEnabled(True)
            if hasattr(self, "progress_bar"):
                self.progress_bar.setVisible(False)
            # Spec §11.4: warning() + detected_medium_label (nicht critical/status_text)
            QMessageBox.warning(
                self,
                t("dialog.invalid_file_title"),
                t("dialog.invalid_file_body", error=_user_msg),
            )
            if hasattr(self, "detected_medium_label"):
                self.detected_medium_label.setText(t("status.invalid_file", file=Path(file_path).name))
            return

        # ── Schwere I/O + Carrier-Forensics in Hintergrundthread ──────────────
        def _bg_load():
            """Läuft komplett im Hintergrundthread – kein Qt-Widget-Aufruf hier.

            Audio-Lade-Kaskade läuft ausschließlich über _load_audio_robust(),
            also backend.api.bridge.get_load_audio_fn() → backend.file_import.
            Damit bleibt der GUI-Release-Pfad im kanonischen Importvertrag;
            direkte soundfile.SoundFile-/pedalboard-/librosa-Pfade gehören in
            backend.file_import, nicht in die Oberfläche.
            """

            def _set_progress(pct: int) -> None:
                """Fortschritt thread-sicher im Haupt-Thread setzen (via Signal)."""
                self._load_progress.emit(pct)

            audio: np.ndarray | None = None
            sr: int = 48000
            try:
                _set_progress(5)
                _loaded_audio, _loaded_sr = _load_audio_robust(str(file_path))
                audio = np.asarray(_loaded_audio, dtype=np.float32)
                sr = int(_loaded_sr)
                _set_progress(95)
            except Exception as _load_exc:
                _msg = str(_load_exc)[:200]

                def _err() -> None:
                    if getattr(self, "_file_load_token", 0) != _load_token:
                        return
                    if str(getattr(self, "current_file_path", "") or "") != str(file_path):
                        return
                    for _bn in ("btn_magic_restoration", "btn_magic_studio"):
                        if hasattr(self, _bn):
                            getattr(self, _bn).setEnabled(True)
                    if hasattr(self, "progress_bar"):
                        self.progress_bar.setRange(0, 10000)
                        self.progress_bar.setValue(0)
                        self.progress_bar.setVisible(False)
                    if hasattr(self, "detected_medium_label"):
                        self.detected_medium_label.setText(
                            t("status.load_failed_with_reason", file=Path(file_path).name, error=_msg)
                        )
                        self.detected_medium_label.setStyleSheet("""
                            color: #B87A7A; font-size: 11pt; padding: 12px;
                            background: rgba(148, 82, 82, 0.10);
                            border-radius: 8px; border: 2px solid rgba(152, 88, 88, 0.26);
                        """)
                    QMessageBox.warning(
                        self,
                        t("dialog.import_failed_title"),
                        t("dialog.import_failed_body", file=Path(file_path).name, error=_msg[:300]),
                    )

                QTimer.singleShot(0, _err)
                return

            if audio is None:
                return

            # Laden vollständig — Balken auf 100 % (letzte Iteration ist bereits 100 %,
            # explizites Setzen als Sicherheitsnetz für Bridge-/Fallback-Pfade)
            _set_progress(100)
            logger.debug("_bg_load: progress 100 emitted, dispatching _on_file_loaded")

            audio = _normalize_audio(audio)

            # Keep native-SR audio for analysis modules (spec: no resampling before analysis)
            _analysis_audio_native = audio
            _analysis_sr_native = int(sr)

            # Resample to 48 kHz — Aurik internal SR (accepts any input SR)
            if sr != 48_000:
                audio = _resample_audio_poly(
                    audio,
                    int(sr),
                    48_000,
                    axis=0 if audio.ndim > 1 else -1,
                )
                sr = 48_000
                audio = _normalize_audio(audio)

            # _on_file_loaded im GUI-Thread starten
            _audio_ref = audio
            _sr_ref = int(sr)
            # Carrier-Ergebnis: Platzhalter → wird asynchron nachgefüllt

            def _apply_loaded(
                _audio=_audio_ref,
                _sr=_sr_ref,
                _fp=file_path,
                _token=_load_token,
            ):
                if getattr(self, "_file_load_token", 0) != _token:
                    return
                _cur_file_norm = os.path.normpath(os.path.realpath(str(getattr(self, "current_file_path", "") or "")))
                _fp_norm = os.path.normpath(os.path.realpath(str(_fp)))
                if _cur_file_norm != _fp_norm:
                    return
                self._on_file_loaded(_audio, _sr, _fp, t("status.analyzing_wait"), 0, load_token=_token)

            self._dispatch_to_gui(_apply_loaded)

            # Temp-store native audio for _pre_analysis_bg (started in _continue_file_loaded).
            # Cleared immediately when _pre_analysis_bg starts (avoids keeping large array on self).
            # Spec: analysis modules run at native import SR — _analysis_audio_native is
            # the pre-resample copy; _analysis_sr_native holds the original file SR.
            self._pa_audio_native = _analysis_audio_native
            self._pa_sr_native = _analysis_sr_native
            # _pre_analysis_bg is defined in _continue_file_loaded and started there.
            # It runs all analyses (medium, era, genre, restorability, defects) in one call.

        threading.Thread(target=_bg_load, daemon=True).start()

    # ── Thread-sichere GUI-Dispatch-Helfer ─────────────────────────────────
    def _dispatch_to_gui(self, fn) -> None:
        """Ruft `fn()` thread-sicher im GUI-Thread auf (via pyqtSignal)."""
        self._gui_dispatch.emit(fn)

    def dispatch_to_gui(self, fn) -> None:
        """Public wrapper for GUI-thread dispatch used by nested worker closures."""
        self._dispatch_to_gui(fn)

    def emit_load_progress(self, pct: float) -> None:
        """Public wrapper for load/pre-analysis progress updates."""
        self._load_progress.emit(float(pct))

    def _safe_gui_invoke(self, fn) -> None:
        """Führt aus: GUI callbacks safely so a single callback cannot crash the UI thread."""
        try:
            fn()
        except Exception:
            logger.exception("Unhandled GUI callback exception was swallowed for stability")

    def _initial_live_quality_mos(self) -> float:
        """Gibt die beste verfügbare Start-Prognose für die Live-Qualitätsanzeige zurück."""
        try:
            if self.current_file_path:
                cached = get_cached_restorability_result(self.current_file_path)
                if cached is not None:
                    return float(np.clip(float(getattr(cached, "predicted_mos", 2.5) or 2.5), 1.0, 5.0))
        except Exception:
            logger.debug("Live-Qualitätsstartwert konnte nicht aus Restorability-Cache gelesen werden", exc_info=True)
        score = float(getattr(self, "_restorability_score", 50.0) or 50.0)
        return float(np.clip(1.0 + np.clip(score, 0.0, 100.0) / 100.0 * 4.0, 1.0, 5.0))

    def _prime_live_quality_meter(self) -> None:
        """Initialisiert die Klangqualitätsanzeige für laufende Restaurierung."""
        if getattr(self, "quality_meter_widget", None) is None:
            return
        mos = self._initial_live_quality_mos()
        self._last_mos_displayed = mos
        self.quality_meter_widget.set_measurement_state(
            "Prognose",
            "Aus Voranalyse und Restaurierbarkeitsmodell abgeleitet; noch kein finaler Export-Messwert.",
        )
        self.quality_meter_widget.set_mos(mos)

    def _set_live_quality_mos(self, mos: float) -> None:
        """Zeigt Pipeline-Fortschritt als explizite Live-Schätzung an."""
        if getattr(self, "quality_meter_widget", None) is None:
            return
        self.quality_meter_widget.set_measurement_state(
            "Live-Schätzung",
            "Laufender Pipeline-Indikator; der finale Messwert ersetzt ihn nach dem Export.",
        )
        self.quality_meter_widget.set_mos(float(mos))

    def _on_load_progress_update(self, pct: float) -> None:
        """Aktualisiert load/pre-analysis progress bar with live percentage display."""
        if not hasattr(self, "progress_bar"):
            return
        _p = float(max(0.0, min(100.0, float(pct))))
        _bar = self.progress_bar

        _cur_file = str(getattr(self, "current_file_path", "") or "")
        _finalized_for = str(getattr(self, "_preanalysis_finalized_for", "") or "")
        _preanalysis_pending = bool(_cur_file and _finalized_for != _cur_file)

        _bar.setRange(0, 10000)
        _bar.setVisible(True)

        if _preanalysis_pending:
            _pct_fmt = f"{_p:.1f}".replace(".", ",") if _p < 99.95 else "100,0"
            _pct_int = int(_p) if _p < 99.8 else 100

            # Datei wird noch geladen — Bar bleibt im Lade-Modus, kein Scan-Text
            if getattr(self, "_is_file_loading", False):
                _bar.setValue(min(10000, int(round(_p * 100.0))))
                return

            if _preanalysis_pending and _p >= 99.8:
                _finalizing_text = "⏳ Analyse wird finalisiert …"
                _bar.setRange(0, 10000)
                _bar.setValue(10000)
                _bar.setFormat(_finalizing_text)
                if hasattr(self, "status_text"):
                    self.status_text.setText(_finalizing_text)
                    if _pct_int != getattr(self, "_last_scan_pct_int", -1):
                        self._last_scan_pct_int = _pct_int
                        self._apply_status_text_style("warning")
                return
            _bar.setValue(min(10000, int(round(_p * 100.0))))
            _bar.setFormat(t("progress.scan_analysis", pct=_pct_fmt))
            # Status-Text: immer denselben _pct_fmt-Wert wie die Bar anzeigen.
            # Throttle nur auf den Style-Aufruf (teuer) — Text selbst ist billig.
            if hasattr(self, "status_text"):
                self.status_text.setText(t("status.defect_scan_progress_text", percent=_pct_fmt))
                if _pct_int != getattr(self, "_last_scan_pct_int", -1):
                    self._last_scan_pct_int = _pct_int
                    self._apply_status_text_style("warning" if _pct_int < 100 else "success")
            return

        _bar.setValue(int(round(_p * 100.0)))
        _bar.setFormat("%p\u202f%")

    def _allow_action(self, action: str, cooldown_ms: int = 250) -> bool:
        """Einfaches flood protection for repeated clicks/shortcuts."""
        now = time.monotonic()
        last = float(self._action_timestamps.get(action, 0.0))
        if now - last < (cooldown_ms / 1000.0):
            return False
        self._action_timestamps[action] = now
        return True

    def _update_carrier_display(
        self,
        carrier_label: str,
        carrier_score: int,
        file_path: str,
        load_token: int | None = None,
    ) -> None:
        """Aktualisiert den Carrier-Label im GUI-Thread (nach async Analyse)."""
        # CRITICAL: State synchronization — _carrier_bg_label MUSS immer mit detected_medium_label synchron sein
        # um nachfolgende Era-Badge-Updates nicht zu zerstören (§2.26, 2026-04-13/2026-04-14 Fix)
        self._carrier_bg_label = carrier_label
        self._carrier_bg_score = carrier_score

        # Feed Prognose-Widget (material key + confidence 0–1)
        if getattr(self, "prognose_widget", None) is not None:
            _raw = getattr(self, "_raw_medium_type", "unknown")
            _conf = float(getattr(self, "_carrier_bg_score", carrier_score)) / 5.0
            self.prognose_widget.update_material(_raw, _conf)  # type: ignore[union-attr]
        if load_token is not None and getattr(self, "_file_load_token", 0) != load_token:
            return
        if str(getattr(self, "current_file_path", "") or "") != str(file_path):
            return
        if hasattr(self, "detected_medium_label"):
            _ampel = self._render_ampel_html(carrier_score)
            # Badge-Reset hier im GUI-Thread (war früher im Carrier-Bg-Thread → Race Condition)
            if not getattr(self, "_era_genre_badge", ""):  # nur bei leerem Badge zurücksetzen
                self._era_genre_badge = ""
            # Era/Genre-Badge mitnehmen, falls bereits berechnet (Race-Condition-Fix)
            _badge = getattr(self, "_era_genre_badge", "")
            self.detected_medium_label.setText(f"{carrier_label}   {_ampel}{_badge}")
            self.detected_medium_label.setStyleSheet("""
                color: #82B89A; font-size: 11pt; padding: 12px;
                background: rgba(85, 155, 115, 0.10);
                border-radius: 8px; border: 2px solid rgba(100, 168, 130, 0.26);
                margin-top: 8px; font-weight: 600; line-height: 1.55;
            """)
        if hasattr(self, "current_detected_carrier"):
            self.current_detected_carrier = carrier_label
        if hasattr(self, "current_carrier_confidence"):
            self.current_carrier_confidence = carrier_score
        self._apply_mode_recommendation_visuals()

    def _apply_authoritative_chain_display(self, chain_keys: list[str]) -> bool:
        """Render an authoritative multi-link carrier chain into the main label.

        §UI-CARRIER-DISPLAY-INVARIANT: Nutzt ausschließlich _build_carrier_chain_html()
        (Modul-Level). Kein lokales _CI_MEDIUM_DATA oder _ci_html().
        """
        if not hasattr(self, "detected_medium_label"):
            return False
        if not isinstance(chain_keys, list) or len(chain_keys) < 2:
            logger.debug(
                "_apply_authoritative_chain_display: übersprungen – len=%d < 2 (chain=%s)",
                len(chain_keys) if isinstance(chain_keys, list) else -1,
                chain_keys,
            )
            return False

        # §UI-CARRIER-DISPLAY-INVARIANT: Modul-Level-Helper nutzen
        _chain_html = _build_carrier_chain_html(chain_keys)
        if not _chain_html:
            return False

        # §UI-CARRIER-DISPLAY-INVARIANT: _carrier_bg_label MUSS synchron bleiben
        self._carrier_bg_label = _chain_html
        _ampel = self._render_ampel_html(int(getattr(self, "_carrier_bg_score", 0) or 0))
        _badge = getattr(self, "_era_genre_badge", "") or ""
        self.detected_medium_label.setText(f"{_chain_html}   {_ampel}{_badge}")
        return True

    @staticmethod
    def _render_star_html(score: int, size: int = 18) -> str:
        """Render star rating as HTML <img> tags using premium star SVG icons (PNG fallback)."""
        _star_dir = os.path.join(os.path.dirname(os.path.dirname(__file__)), "resources", "star_icons")

        def _star_path(stem: str) -> str:
            _svg = os.path.join(_star_dir, f"{stem}.svg")
            _png = os.path.join(_star_dir, f"{stem}.png")
            return _svg if os.path.isfile(_svg) else _png

        _full = _star_path("star_full")
        _empty = _star_path("star_empty")
        parts = []
        for i in range(5):
            _p = _full if i < score else _empty
            parts.append(f'<img src="file:///{_p}" width="{size}" height="{size}" style="vertical-align:middle;">')
        return "".join(parts)

    @staticmethod
    def _render_ampel_html(score: int) -> str:
        """Render carrier detection confidence as a single Ampel (traffic-light) colour dot.

        Replaces the 5-star display for the carrier badge because it is more
        readable at small label sizes and visually consistent with the genre
        confidence dot already used in the era/genre badge.

        Score mapping (0-5):
          4–5 → green  (#3ECF8E) — high detection confidence
          2–3 → amber  (#F6C453) — medium confidence
          0–1 → red    (#FF6B6B) — low / uncertain
        """
        if score >= 4:
            _col = "#3ECF8E"
        elif score >= 2:
            _col = "#F6C453"
        else:
            _col = "#FF6B6B"
        return f'<span style="color:{_col};font-size:13pt;vertical-align:middle;">&#9679;</span>'

    def _on_file_loaded(  # pylint: disable=too-many-positional-arguments
        self,
        audio: np.ndarray,
        sr: int,
        file_path: str,
        carrier_label: str,
        carrier_score: int,
        load_token: int | None = None,
    ):
        """Wird im Haupt-Thread aufgerufen, nachdem sf.read + Carrier-Forensics fertig sind."""
        if load_token is not None and getattr(self, "_file_load_token", 0) != load_token:
            return
        if str(getattr(self, "current_file_path", "") or "") != str(file_path):
            return

        logger.debug("_on_file_loaded called: audio.shape=%s sr=%d", audio.shape, sr)
        self._is_file_loading = False  # Datei vollständig geladen — Bar zeigt ab jetzt Scan-%
        # Lade-Zustand des WaveformWidgets aufheben
        if hasattr(self, "waveform_widget"):
            self.waveform_widget.is_loading = False
        # Fortschrittsbalken: 100 % sichtbar anzeigen
        if hasattr(self, "progress_bar"):
            self.progress_bar.setValue(10000)
            self.progress_bar.setFormat("100,00 % - " + t("status.import_done"))

        # Export-Dialog jetzt MODAL und BLOCKIEREND vor jeglicher Verarbeitung
        logger.debug("_on_file_loaded: opening ExportConfigDialog (modal)")

        # Export Preset dialog — try preset selection first
        try:
            from Aurik10.ui.export_presets import ExportPresetDialog

            preset_dlg = ExportPresetDialog(self)
            if preset_dlg.exec_() == QDialog.DialogCode.Accepted:
                self._export_config = preset_dlg.get_config()
                _cfg_out_dir = str(self._export_config.get("output_dir", "") or "").strip()
                if _cfg_out_dir:
                    self._output_dir = _cfg_out_dir
                if hasattr(self, "progress_bar"):
                    self.progress_bar.setVisible(False)
                    self.progress_bar.setValue(0)
                self._continue_file_loaded(audio, sr, file_path, carrier_label, carrier_score, load_token=load_token)
                return
        except Exception:
            logger.debug("fallback in modern_window.py", exc_info=True)
        # Fall through to existing ExportConfigDialog

        _dlg = ExportConfigDialog(file_path, parent=self)
        if _dlg.exec() != QDialog.DialogCode.Accepted:
            if hasattr(self, "progress_bar"):
                self.progress_bar.setVisible(False)
                self.progress_bar.setValue(0)
            if hasattr(self, "status_text"):
                self.status_text.setText(t("status.import_cancelled"))
            return
        self._export_config = _dlg.get_config()
        _cfg_out_dir = str(self._export_config.get("output_dir", "") or "").strip()
        if _cfg_out_dir:
            self._output_dir = _cfg_out_dir
        if hasattr(self, "progress_bar"):
            self.progress_bar.setVisible(False)
            self.progress_bar.setValue(0)
        # Jetzt erst Hintergrundverarbeitung starten
        self._continue_file_loaded(audio, sr, file_path, carrier_label, carrier_score, load_token=load_token)

    def _continue_file_loaded(
        self,
        audio: "np.ndarray",
        sr: int,
        file_path: str,
        _carrier_label: str,
        _carrier_score: int,
        load_token: int | None = None,
    ):
        """Setzt _on_file_loaded nach dem Export-Dialog fort (UI-Block)."""
        try:
            if load_token is not None and getattr(self, "_file_load_token", 0) != load_token:
                return
            if str(getattr(self, "current_file_path", "") or "") != str(file_path):
                return
            _audio = _normalize_audio(audio)
            _sr = int(sr)
            # A/B-Player: Original speichern
            self._orig_audio = _audio
            self._orig_sr = _sr
            self._rest_audio = None  # zurücksetzen nach neuem File
            # Live-Preview zurücksetzen — kein Zwischenstand vom vorherigen Song
            self._live_preview_audio = None
            self._live_preview_sr = 48000

            # A/B Preview widget: show after file loaded, initially hidden
            try:
                from Aurik10.ui.ab_preview import ABPreviewWidget

                if not hasattr(self, "_ab_preview_widget") or self._ab_preview_widget is None:
                    self._ab_preview_widget = ABPreviewWidget(self)
                    self._ab_preview_widget.restoration_requested.connect(lambda mode: self._process_with_mode(mode))
                    if hasattr(self, "_main_area_layout"):
                        self._main_area_layout.addWidget(self._ab_preview_widget)
                self._ab_preview_widget.setVisible(True)
            except Exception:
                logger.debug("fallback in modern_window.py", exc_info=True)

            # Playback pre-warmup: resample to device SR in background so the
            # first play-click is stutter-free.  Invalidate any previous cache.
            self._playback_device_cache = None
            self._playback_warmup_token += 1
            # Invalidate streaming player resample cache for the new file
            _sp = getattr(self, "_streaming_player", None)
            if _sp is not None:
                try:
                    _sp.invalidate_cache()
                except Exception:
                    logger.debug("Datei-Laden: Streaming-Player-Cache konnte nicht invalidiert werden", exc_info=True)
            _warmup_token = self._playback_warmup_token
            _warmup_audio = _audio
            _warmup_sr = _sr

            def _warmup_device_cache(
                _w_audio=_warmup_audio,
                _w_sr=_warmup_sr,
                _w_token=_warmup_token,
            ) -> None:
                """Pre-resample audio to output device SR and cache it.

                Runs in a daemon thread immediately after the file loads.
                Eliminates the real-time resample that caused stutter on the
                first play-click with PulseAudio/ALSA bridges.
                """
                try:
                    if not _SD_AVAILABLE or _sd is None:
                        return
                    _dev = _sd.query_devices(kind="output")
                    _dev_sr = int(round(float(_dev.get("default_samplerate", 0.0)))) if isinstance(_dev, dict) else 0

                    # Prepare float32 contiguous data
                    data = np.ascontiguousarray(_w_audio, dtype=np.float32)
                    if data.ndim == 1:
                        data = data.reshape(-1, 1)
                    if _dev_sr > 0 and abs(_dev_sr - _w_sr) >= 2000:
                        data = _resample_audio_poly(data, _w_sr, _dev_sr, axis=0)
                        cached_sr = _dev_sr
                    else:
                        cached_sr = _w_sr
                    data = np.ascontiguousarray(data, dtype=np.float32)
                    # Staleness guard — discard if user already loaded another file
                    if getattr(self, "_playback_warmup_token", 0) != _w_token:
                        return
                    self._playback_device_cache = (id(_w_audio), _w_sr, cached_sr, data)
                    logger.debug(
                        "Playback warmup done: source_sr=%d → device_sr=%d, shape=%s",
                        _w_sr,
                        cached_sr,
                        data.shape,
                    )
                except Exception as _exc:
                    logger.debug("Playback warmup cache failed (non-blocking): %s", _exc)

            threading.Thread(target=_warmup_device_cache, daemon=True).start()

            # ── Pre-Analyse-Synchronisation (Defektanalyse + Ära/Genre) ──────────
            # Both analysis threads must complete before Magic Buttons are enabled.
            # _finalize_preanalysis() is called when both flags are set (or 15 s timeout).
            _cfk = str(file_path)  # canonical file-key for stale-signal guard
            # Snap the load token so closures can detect when a NEWER load has started
            # for the SAME file (same _cfk). This is the primary staleness guard.
            _snap_token: int = int(load_token) if load_token is not None else 0

            def _finalize_preanalysis() -> None:
                """Aktiviert magic buttons and show final status. Must run on GUI thread."""
                # Primary guard: token mismatch means a newer _continue_file_loaded
                # invocation exists for the same file — discard this stale closure.
                if getattr(self, "_file_load_token", 0) != _snap_token:
                    return
                if str(getattr(self, "current_file_path", "")) != _cfk:
                    return
                if bool(self.batch_thread and self.batch_thread.isRunning()):
                    return
                if getattr(self, "_preanalysis_finalized_for", None) == _cfk:
                    return  # double-fire guard
                self._preanalysis_finalized_for = _cfk
                self._apply_mode_recommendation_visuals()
                # Self-healing sync: if background UI update arrived late, refresh
                # cards from cached analysis state before announcing completion.
                try:
                    if hasattr(self, "defect_summary_label"):
                        _cur_defect_txt = str(self.defect_summary_label.text() or "").strip()
                        _still_analyzing = {
                            t("status.defects_summary_analyzing"),
                            t("status.analyzing_wait"),
                            t("ui.no_analysis"),
                            "Schäden werden analysiert …",
                            "🔄\u2002Schäden werden analysiert …",
                        }
                        if _cur_defect_txt in _still_analyzing:
                            _cached_scan = get_cached_defect_result(_cfk)
                            if _cached_scan is not None and hasattr(_cached_scan, "scores"):
                                _disp = _defect_analysis_to_display(_cached_scan.scores, status="detected")
                                self._update_defects(_disp)
                    if hasattr(self, "detected_medium_label"):
                        _cur_med_txt = str(self.detected_medium_label.text() or "").strip()
                        if _cur_med_txt in {"", t("status.analyzing_wait")}:
                            _lbl = str(getattr(self, "_carrier_bg_label", "") or "").strip()
                            _sc = int(getattr(self, "_carrier_bg_score", 0) or 0)
                            if _lbl and _lbl != t("status.analyzing_wait"):
                                self._update_carrier_display(_lbl, _sc, _cfk, load_token=_snap_token)
                except Exception as _sync_exc:
                    logger.debug("Pre-analysis finalize: UI sync fallback failed: %s", _sync_exc)
                if hasattr(self, "progress_bar"):
                    self.progress_bar.setRange(0, 10000)
                    self.progress_bar.setValue(10000)
                    self.progress_bar.setFormat("100,00 % - " + t("status.defect_scan_done"))

                    def _reset_progress_if_idle() -> None:
                        if self.batch_thread and self.batch_thread.isRunning():
                            return
                        self.progress_bar.setVisible(False)
                        self.progress_bar.setValue(0)

                    QTimer.singleShot(1500, _reset_progress_if_idle)
                if hasattr(self, "status_text"):
                    _fname = Path(getattr(self, "current_file_path", "") or "").name
                    _rec = getattr(self, "_recommended_mode", "RESTORATION")
                    _rec_lbl = "Restoration" if _rec == "RESTORATION" else "Studio 2026"
                    _msg = (
                        f"{_fname} — Analyse abgeschlossen. Empfehlung: {_rec_lbl} · Modus wählen und starten."
                        if _fname
                        else "Analyse abgeschlossen — Modus wählen und starten."
                    )
                    self.status_text.setText(_msg)
                    self._apply_status_text_style("success")
                self._set_magic_buttons_enabled(True)

            def _fail_closed_preanalysis(reason: str) -> None:
                """Fail-closed bei Voranalysefehler: Buttons bleiben gesperrt, kein stiller Bypass."""
                if getattr(self, "_file_load_token", 0) != _snap_token:
                    return
                if str(getattr(self, "current_file_path", "")) != _cfk:
                    return
                self._preanalysis_finalized_for = _cfk
                self._set_magic_buttons_enabled(False)
                if hasattr(self, "progress_bar"):
                    self.progress_bar.setRange(0, 10000)
                    self.progress_bar.setValue(0)
                    self.progress_bar.setVisible(False)
                if hasattr(self, "status_text"):
                    self.status_text.setText(
                        f"Voranalyse fehlgeschlagen ({reason}) — Bridge prüfen und Datei neu laden."
                    )
                    self._apply_status_text_style("error")
                if hasattr(self, "detected_medium_label"):
                    self.detected_medium_label.setText(
                        "Voranalyse fehlgeschlagen — Start aus Sicherheitsgründen blockiert"
                    )
                    self.detected_medium_label.setStyleSheet("""
                        color: #B87A7A; font-size: 11pt; padding: 12px;
                        background: rgba(148, 82, 82, 0.10);
                        border-radius: 8px; border: 2px solid rgba(152, 88, 88, 0.26);
                    """)

            def _try_signal_preanalysis_done(flag: str) -> None:
                """Signalisiert one pre-analysis step as done. Must run on GUI thread."""
                # Primary guard: token mismatch → stale closure from previous load of same file.
                if getattr(self, "_file_load_token", 0) != _snap_token:
                    return
                _cur_file_norm = os.path.normpath(os.path.realpath(str(getattr(self, "current_file_path", "") or "")))
                _cfk_norm = os.path.normpath(os.path.realpath(str(_cfk)))
                if _cur_file_norm != _cfk_norm:
                    return  # stale signal from previous file
                if getattr(self, "_preanalysis_finalized_for", None) == _cfk:
                    return  # already finalized — suppress duplicate calls
                self._preanalysis_flags.add(flag)
                _both_done = {"defect_scan", "era_genre"} <= self._preanalysis_flags
                if _both_done or getattr(self, "_preanalysis_timeout_fired", False):
                    _finalize_preanalysis()
                elif "defect_scan" in self._preanalysis_flags:
                    # Defect scan done but era/genre still running → marquee (indeterminate)
                    # DO NOT set a fixed value here — setValue(9950) caused the "permanent
                    # 99,0 %" display bug: bar jumped to 99.50 % and stayed there the entire
                    # time era/genre detection ran (could be many seconds).
                    if hasattr(self, "progress_bar"):
                        self.progress_bar.setRange(0, 0)  # Qt marquee / busy-indicator mode
                        self.progress_bar.setFormat(t("status.era_genre_detecting"))
                        self.progress_bar.setVisible(True)
                    if hasattr(self, "status_text"):
                        self.status_text.setText(t("status.era_genre_detecting"))
                        self._apply_status_text_style("warning")
                elif "era_genre" in self._preanalysis_flags:
                    # Era/genre done but defect scan still running → percentage continues via _on_load_progress_update
                    pass

            # Restaurierbarkeits-Banner zurücksetzen (neues File)
            if hasattr(self, "restorability_banner"):
                self.restorability_banner.setText(t("ui.analyzing_wait_short"))
                self.restorability_banner.setStyleSheet("""
                    color: #6080A0; font-size: 8pt; padding: 5px 8px;
                    background: rgba(70, 90, 130, 0.08);
                    border-radius: 8px; border: 1px solid rgba(70, 90, 130, 0.15);
                """)
                self.restorability_banner.setVisible(True)

            # Carrier placeholder — _pre_analysis_bg will fill detected_medium_label
            # with the correct carrier chain + era/genre badge once all analyses complete.
            if hasattr(self, "detected_medium_label"):
                self.detected_medium_label.setText(t("status.analyzing_wait"))
                self.detected_medium_label.setStyleSheet("""
                    color: #7B93B8; font-size: 11pt; padding: 12px;
                    background: rgba(102, 126, 234, 0.10);
                    border-radius: 8px; border: 2px solid rgba(102, 126, 234, 0.22);
                """)

            self._update_waveform(_audio, _sr)
            # A/B Original-Waveform direkt beim Öffnen befüllen (nicht erst nach Restaurierung)
            if hasattr(self, "waveform_widget_orig_ab"):
                with contextlib.suppress(Exception):
                    self.waveform_widget_orig_ab.update_waveform(_audio, _sr)
            # A/B-Buttons aktivieren
            self._update_ab_player_state()

            # ── Unified pre-analysis background thread ─────────────────────
            # Replaces _carrier_bg (ex _bg_load), _detect_era_genre_bg,
            # _estimate_restorability_bg and _run_defect_scan_bg.
            # run_pre_analysis() handles all 5 analyses (medium, era, genre,
            # restorability, defects) in parallel at native import SR per spec.

            # Sofortiges Feedback im Haupt-Thread → Nutzer sieht direkt, dass
            # die Analyse läuft (kein leeres Label bis der Thread fertig ist).
            if hasattr(self, "defect_summary_label"):
                self.defect_summary_label.setText(t("status.defects_summary_analyzing"))
                self.defect_summary_label.setStyleSheet("""
                    color: #90A4AE; font-size: 10pt; padding: 12px;
                    background: rgba(144, 164, 174, 0.10);
                    border-radius: 10px; border: 1px solid rgba(144, 164, 174, 0.25);
                """)
            if hasattr(self, "defect_count_live_label"):
                self.defect_count_live_label.setText(t("status.analyzing_short"))
                self.defect_count_live_label.setStyleSheet(
                    "color: #90A4AE; font-size: 8pt; background: transparent; padding: 0 2px;"
                )
                self.defect_count_live_label.setVisible(True)
            if hasattr(self, "progress_bar"):
                self.progress_bar.setRange(0, 10000)
                self.progress_bar.setValue(0)
                self.progress_bar.setFormat("0,00 % - " + t("status.defects_progress"))
                self.progress_bar.setVisible(True)
            if hasattr(self, "status_text"):
                self.status_text.setText(t("status.defects_analyzing"))
                self._apply_status_text_style("warning")

            _fp_pre = str(file_path)
            _token_pre = int(_snap_token)
            _audio_native_default = getattr(self, "_pa_audio_native", _audio)
            _sr_native_default = getattr(self, "_pa_sr_native", int(_sr))

            def _pre_analysis_bg(
                _audio_48k=_audio,
                _sr_48k=int(_sr),
                _audio_native=_audio_native_default,
                _sr_native=_sr_native_default,
                _file_key=_fp_pre,
                _token=_token_pre,
            ):
                # Clear temporary native audio reference immediately to avoid keeping
                # a large array on the instance beyond the lifetime of this thread.
                self._pa_audio_native = None
                self._pa_sr_native = 0

                _logger_ = logger

                # §UI-CARRIER-DISPLAY-INVARIANT: Modul-Level-Konstanten verwenden —
                # KEIN lokales Redefinieren von _MEDIUM_DATA/_CI_MEDIUM_DATA oder _html()/_ci_html().
                # Alle Carrier-Display-Pfade nutzen: _CARRIER_MEDIUM_DISPLAY, _CARRIER_EXT_DISPLAY,
                # _CARRIER_ANALOG_MEDIA, _render_carrier_html(), _build_carrier_chain_html()

                def _on_scan_progress(pct: float) -> None:
                    self.emit_load_progress(float(pct))

                # ── Run all analyses via unified backend entry point ──────────
                if _bridge_run_pre_analysis is None:
                    _logger_.error("_pre_analysis_bg: run_pre_analysis nicht importierbar")
                    self.dispatch_to_gui(lambda: _fail_closed_preanalysis("Bridge-Import fehlt"))
                    return
                try:
                    _result = _bridge_run_pre_analysis(
                        _audio_native,
                        _sr_native,
                        audio_48k=_audio_48k,
                        file_path=_file_key,
                        scan_progress_callback=_on_scan_progress,
                        store_in_bridge_cache=True,
                    )
                except Exception as _pre_exc:  # pylint: disable=broad-except
                    _logger_.error("_pre_analysis_bg: run_pre_analysis fehlgeschlagen: %s", _pre_exc)
                    self.dispatch_to_gui(lambda _msg=str(_pre_exc): _fail_closed_preanalysis(_msg))
                    return

                # Staleness guard — discard result if user switched file during analysis
                if getattr(self, "_file_load_token", 0) != _token:
                    return
                _cur_file_norm = os.path.normpath(os.path.realpath(str(getattr(self, "current_file_path", "") or "")))
                _file_key_norm = os.path.normpath(os.path.realpath(str(_file_key)))
                if _cur_file_norm != _file_key_norm:
                    return

                # Direktes Handover für den Modus-Klick: nutzt das echte PreAnalysisResult,
                # unabhängig vom Bridge-Cache-Timing.
                # WICHTIG: Path MUSS normalisiert sein für später Vergleiche
                self._latest_pre_analysis_result = _result
                _normalized_file = os.path.normpath(os.path.realpath(str(_file_key)))
                self._latest_pre_analysis_file = _normalized_file
                logger.debug(
                    "_pre_analysis_bg: Speichern PreAnalysisResult für normalisiertes Path: %s",
                    _normalized_file,
                )

                if _result is None:
                    self.dispatch_to_gui(lambda: _fail_closed_preanalysis("leeres Pre-Analysis-Ergebnis"))
                    return

                # ── Build carrier HTML from result.medium ────────────────────
                # §UI-CARRIER-DISPLAY-INVARIANT: Modul-Level-Helpers nutzen.
                _med = _result.medium  # type: ignore[union-attr]
                _raw_medium = getattr(_med, "primary_material", None) or "unknown"
                _score = round(float(getattr(_med, "confidence", 0)) * 5) if _med else 0
                _chain_keys: list[str] = list(getattr(_med, "transfer_chain", None) or [])
                _orig_stem, _orig_label = _CARRIER_MEDIUM_DISPLAY.get(_raw_medium, ("unknown", _raw_medium))
                _orig_html = _render_carrier_html(_orig_stem, _orig_label)
                if len(_chain_keys) > 1:
                    # MediumDetector hat vollständige Kette — direkt verwenden
                    _lbl = _build_carrier_chain_html(_chain_keys)
                elif len(_chain_keys) == 1:
                    # Einzel-Eintrag: analog? → Dateiendung als Container anhängen
                    _ext = Path(_file_key).suffix.lower()
                    _ext_entry = _CARRIER_EXT_DISPLAY.get(_ext)
                    if _ext_entry and _raw_medium in _CARRIER_ANALOG_MEDIA:
                        _lbl = f"{_orig_html}&nbsp;&nbsp;→&nbsp;&nbsp;{_render_carrier_html(*_ext_entry)}"
                    else:
                        _lbl = _orig_html
                else:
                    # Leere Kette: Analog-Medium + Dateiendung als Fallback
                    _ext = Path(_file_key).suffix.lower()
                    _ext_entry = _CARRIER_EXT_DISPLAY.get(_ext)
                    if _ext_entry and _raw_medium in _CARRIER_ANALOG_MEDIA:
                        _lbl = f"{_orig_html}&nbsp;&nbsp;→&nbsp;&nbsp;{_render_carrier_html(*_ext_entry)}"
                    else:
                        _lbl = _orig_html

                # ── Build era/genre badge ────────────────────────────────────
                decade_label = ""
                genre_label = ""
                genre_confidence: float | None = None
                genre_lang_score: float | None = None
                genre_lang_dsp: float | None = None
                genre_lang_lyrics: float | None = None
                genre_family_label: str = ""
                genre_family_confidence: float | None = None
                genre_topk: list[tuple[str, float]] = []
                genre_open_set_unknown: bool | None = None
                _raw_decade: int | None = None
                _floor_decade: int | None = None
                _era_floor_applied = False

                er = _result.era
                if er is not None:
                    _raw_dec = getattr(er, "decade", None) or (er.get("decade") if isinstance(er, dict) else None)
                    if isinstance(_raw_dec, (int, float)):
                        _raw_decade = int(_raw_dec)
                    # §Medium-Floor-Constraint: displayed era >= medium invention date
                    if _raw_medium and _raw_medium not in ("unknown", ""):
                        try:
                            _MEDIUM_DECADE_FLOOR, _era_floor_fn = _bridge_get_era_medium_constraint()
                            er_constrained = _era_floor_fn(er, str(_raw_medium))
                            _floor_decade = _MEDIUM_DECADE_FLOOR.get(str(_raw_medium).strip().lower())
                            _cdec = getattr(er_constrained, "decade", None) or (
                                er_constrained.get("decade") if isinstance(er_constrained, dict) else None
                            )
                            if _cdec:
                                _dec_i = int(_cdec)
                                if _raw_decade is not None and _dec_i != _raw_decade:
                                    _era_floor_applied = True
                                if _era_floor_applied and _floor_decade is not None and _dec_i == _floor_decade:
                                    decade_label = f"{_floor_decade}er"
                                else:
                                    decade_label = f"{_dec_i}er"
                        except Exception:
                            if _raw_decade:
                                decade_label = f"{_raw_decade}er"
                    else:
                        if _raw_decade:
                            decade_label = f"{_raw_decade}er"

                gr = _result.genre
                if gr is not None:
                    _g_conf = getattr(gr, "confidence", None)
                    if isinstance(_g_conf, (int, float)):
                        genre_confidence = float(_g_conf)
                    _g_lang = getattr(gr, "vocal_language_score", None)
                    if isinstance(_g_lang, (int, float)):
                        genre_lang_score = float(_g_lang)
                    _g_lang_dsp = getattr(gr, "dsp_language_score", None)
                    if isinstance(_g_lang_dsp, (int, float)):
                        genre_lang_dsp = float(_g_lang_dsp)
                    _g_lang_lyrics = getattr(gr, "lyrics_language_hint", None)
                    if isinstance(_g_lang_lyrics, (int, float)):
                        genre_lang_lyrics = float(_g_lang_lyrics)
                    _g_family = getattr(gr, "genre_family", None)
                    if isinstance(_g_family, str):
                        genre_family_label = _g_family
                    _g_family_conf = getattr(gr, "genre_family_confidence", None)
                    if isinstance(_g_family_conf, (int, float)):
                        genre_family_confidence = float(_g_family_conf)
                    _g_top = getattr(gr, "top_genres", None)
                    if isinstance(_g_top, (list, tuple)):
                        for _item in _g_top:
                            if isinstance(_item, (list, tuple)) and len(_item) == 2:
                                _gl, _gc = str(_item[0]), _item[1]
                                if isinstance(_gc, (int, float)):
                                    genre_topk.append((_gl, float(_gc)))
                    _g_open = getattr(gr, "open_set_unknown", None)
                    if isinstance(_g_open, bool):
                        genre_open_set_unknown = _g_open
                    _gl = getattr(gr, "genre_label", None) or (gr.get("genre_label") if isinstance(gr, dict) else None)
                    if _gl and _gl.lower() not in ("unbekannt", "unknown", ""):
                        genre_label = str(_gl)
                    if not genre_label and getattr(gr, "is_schlager", False):
                        genre_label = "Schlager"
                    if not genre_label and genre_topk:
                        _top_g, _top_c = genre_topk[0]
                        if _top_g and _top_g.lower() not in ("unbekannt", "unknown", ""):
                            genre_label = _top_g
                            if genre_confidence is None:
                                genre_confidence = _top_c

                badge = ""
                if decade_label or genre_label:
                    _era_segs = []
                    if decade_label:
                        _era_segs.append('<span style="color:#82B89A;">◷ ' + decade_label + "</span>")
                    if genre_label:
                        _g_conf_v = float(genre_confidence) if isinstance(genre_confidence, (int, float)) else None
                        if _g_conf_v is None:
                            _ampel_color = "#8A9AA9"
                        elif _g_conf_v >= 0.70:
                            _ampel_color = "#3ECF8E"
                        elif _g_conf_v >= 0.50:
                            _ampel_color = "#F6C453"
                        else:
                            _ampel_color = "#FF6B6B"
                        _era_segs.append(
                            '<span style="color:#82B89A;">Genre: '
                            + genre_label
                            + '&nbsp;<span style="color:'
                            + _ampel_color
                            + ';">&#9679;</span></span>'
                        )
                    _era_sep = '<span style="color:#6E839D;">&nbsp;·&nbsp;</span>'
                    badge = (
                        '<br><span style="font-size:9pt;font-weight:600;letter-spacing:0.1px;">'
                        + _era_sep.join(_era_segs)
                        + "</span>"
                    )

                # ── Build era/genre tooltip ──────────────────────────────────
                _carrier_name = _CARRIER_MEDIUM_DISPLAY.get(str(_raw_medium), ("unknown", str(_raw_medium)))[1]
                tip_era = (
                    f"<b>Träger-Forensik &amp; Aufnahme-Epoche</b><br>Erkanntes Medium: <b>{_carrier_name}</b><br>"
                )
                if decade_label:
                    tip_era += f"Aufnahme-Ära: <b>{decade_label}</b><br>"
                if _era_floor_applied and _raw_decade is not None and _floor_decade is not None:
                    tip_era += (
                        f"<small>Hinweis: Rohschätzung {_raw_decade}er, "
                        f"mediumbedingt auf &gt;= {_floor_decade}er begrenzt.</small><br>"
                    )
                if genre_label:
                    tip_era += f"Genre: <b>{genre_label}</b><br>"
                if genre_family_label:
                    _fam_conf_txt = (
                        f" ({genre_family_confidence:.2f})" if isinstance(genre_family_confidence, (int, float)) else ""
                    )
                    tip_era += f"Genre-Familie: <b>{genre_family_label}</b>{_fam_conf_txt}<br>"
                if genre_topk:
                    _topk_txt = " · ".join(f"{lbl} {sc:.2f}" for lbl, sc in genre_topk[:3])
                    tip_era += f"Top-Genres: <b>{_topk_txt}</b><br>"
                if isinstance(genre_open_set_unknown, bool):
                    tip_era += (
                        "Open-Set: <b>unknown</b><br>" if genre_open_set_unknown else "Open-Set: <b>known</b><br>"
                    )
                if genre_confidence is not None:
                    tip_era += f"Genre-Sicherheit: <b>{genre_confidence:.2f}</b><br>"
                if genre_lang_score is not None:
                    tip_era += f"DE-Sprachscore (gesamt): <b>{genre_lang_score:.2f}</b><br>"
                if genre_lang_dsp is not None or genre_lang_lyrics is not None:
                    _dsp_txt = f"{genre_lang_dsp:.2f}" if genre_lang_dsp is not None else "—"
                    _lyr_txt = f"{genre_lang_lyrics:.2f}" if genre_lang_lyrics is not None else "—"
                    tip_era += f"Sprachanteile: DSP <b>{_dsp_txt}</b> · Lyrics <b>{_lyr_txt}</b><br>"
                tip_era += "<small>Die Ära-Erkennung passt alle Restaurierungs-Parameter historisch korrekt an.</small>"

                # ── Build restorability banner ───────────────────────────────
                _rest_result = _result.restorability
                score100: float = 50.0
                predicted_mos: float = 3.5
                limiting: list = []
                if _rest_result is not None:
                    score100 = float(getattr(_rest_result, "restorability_score", 50.0))
                    predicted_mos = float(getattr(_rest_result, "predicted_mos", 3.5))
                    limiting = list(getattr(_rest_result, "limiting_defects", []))
                else:
                    # DSP fallback
                    _mono_fb = np.mean(_audio_48k, axis=0) if _audio_48k.ndim == 2 else _audio_48k
                    _rms = float(np.sqrt(np.mean(_mono_fb.astype(np.float64) ** 2))) + 1e-12
                    _noise = float(np.percentile(np.abs(_mono_fb.astype(np.float64)), 5)) + 1e-12
                    _snr_db = 20.0 * np.log10(_rms / _noise)
                    score100 = float(np.clip((_snr_db - 8.0) / 35.0 * 100.0, 5.0, 98.0))
                    predicted_mos = round(1.0 + score100 / 100.0 * 4.0, 1)
                if score100 >= 70:
                    _s_color = "#82B89A"
                    _bg_r = "rgba(85, 155, 115, 0.14)"
                    _border_r = "rgba(100, 168, 130, 0.36)"
                    _zeile1 = f"▶  Sehr gut restaurierbar  ({score100:.0f}\u202f/\u202f100)"
                    _detail = "Aurik kann diese Aufnahme auf exzellentem Niveau restaurieren."
                elif score100 >= 40:
                    _s_color = "#B8A068"
                    _bg_r = "rgba(150, 130, 68, 0.14)"
                    _border_r = "rgba(150, 130, 68, 0.36)"
                    _zeile1 = f"▶  Mäßig restaurierbar  ({score100:.0f}\u202f/\u202f100)"
                    _detail = "Deutliche Verbesserung möglich – Restschäden können bleiben."
                else:
                    _s_color = "#B87A7A"
                    _bg_r = "rgba(148, 82, 82, 0.14)"
                    _border_r = "rgba(152, 88, 88, 0.36)"
                    _zeile1 = f"▶  Stark beschädigt  ({score100:.0f}\u202f/\u202f100)"
                    _detail = "Material ist sehr stark beschädigt – Aurik holt das physikalisch Mögliche heraus."
                _mos_str = f"{predicted_mos:.1f}"
                # MOS-Wert → Klartext-Qualitätsbewertung für Laien
                if predicted_mos >= 4.5:
                    _quality_label = "hervorragend"
                elif predicted_mos >= 4.0:
                    _quality_label = "sehr gut"
                elif predicted_mos >= 3.5:
                    _quality_label = "gut"
                elif predicted_mos >= 3.0:
                    _quality_label = "ordentlich"
                else:
                    _quality_label = "eingeschränkt"
                _banner_txt = (
                    f"{_zeile1}    ·    Erwartete Klangqualität:  {_quality_label}  "
                    f"({_mos_str}\u202f/\u202f5,0)\n{_detail}"
                )
                if limiting:
                    _banner_txt += f"    (Größte Schäden: {', '.join(str(d) for d in limiting[:2])})"
                _tip_rest_extra = ""
                if _rest_result is not None:
                    _snr_v = getattr(_rest_result, "snr_db", None)
                    _grade_v = getattr(_rest_result, "grade", None)
                    _time_v = getattr(_rest_result, "processing_time_estimate_s", None)
                    if _snr_v is not None:
                        _tip_rest_extra += f"Signal-Rausch-Abstand: <b>{_snr_v:.0f}\u202fdB</b><br>"
                    if _grade_v is not None:
                        _tip_rest_extra += f"Stufe: <b>{_grade_v}</b><br>"
                    if _time_v is not None:
                        _tip_rest_extra += (
                            f"Geschätzte Dauer: <b>~{int(_time_v // 60)}\u202fMin."
                            f"\u202f{int(_time_v % 60)}\u202fSek.</b><br>"
                        )
                _tip_rest = (
                    f"<b>Restaurierbarkeits-Vorschätzung</b><br>"
                    f"Wert: <b>{score100:.0f}\u202f/\u202f100</b><br>"
                    f"Erwartete Klangqualität: <b>{_quality_label} ({_mos_str}\u202f/\u202f5,0)</b><br>"
                    f"{_tip_rest_extra}"
                    f"<small>Schnelle Vorab-Analyse – "
                    f"vor dem eigentlichen Restaurierungsvorgang.</small>"
                )
                _css_rest = (
                    f"color:{_s_color}; font-size:10pt; font-weight:600;"
                    f" padding:10px 18px; border-radius:10px;"
                    f" background:{_bg_r}; border:1px solid {_border_r};"
                )

                # ── Build defect display dict ────────────────────────────────
                _scan = _result.defects
                if _scan is not None:
                    _defects = _defect_analysis_to_display(_scan.scores, status="detected")
                else:
                    _defects = {
                        "clicks": 0,
                        "crackle": 0,
                        "pops": 0,
                        "clipping": 0,
                        "sibilance": 0,
                        "dropout": 0,
                        "hum": 0.0,
                        "noise_level": 0.0,
                        "wow": 0.0,
                        "flutter": 0.0,
                        "rumble": 0.0,
                        "status": "detected",
                    }
                _defects_payload = dict(_defects)

                # ── Single GUI dispatch (all UI updates at once) ──────────────
                def _update_all(
                    _lbl=_lbl,
                    _sc=_score,
                    _raw_med=_raw_medium,
                    _badge=badge,
                    _tip_e=tip_era,
                    _era_decade=decade_label,
                    _era_genre=genre_label,
                    _banner=_banner_txt,
                    _css_r=_css_rest,
                    _tip_r=_tip_rest,
                    _rest_r=_rest_result,
                    _rest_score=score100,
                    _defects=None,
                ):
                    _defects = _defects_payload if _defects is None else _defects
                    # Token guard inside GUI thread
                    if getattr(self, "_file_load_token", 0) != _token:
                        return
                    _cur_file_norm = os.path.normpath(
                        os.path.realpath(str(getattr(self, "current_file_path", "") or ""))
                    )
                    _file_key_norm = os.path.normpath(os.path.realpath(str(_file_key)))
                    if _cur_file_norm != _file_key_norm:
                        return

                    # -- Carrier --
                    self._carrier_bg_label = _lbl
                    self._carrier_bg_score = _sc
                    self._raw_medium_type = _raw_med
                    self._update_carrier_display(_lbl, _sc, _file_key, load_token=_token)

                    # -- Era/Genre badge appended to carrier label --
                    _ampel_c = self._render_ampel_html(_sc)
                    self._era_genre_badge = _badge
                    self._era_genre_cached = str(_era_genre or "")
                    self.detected_medium_label.setStyleSheet("""
                        color: #82B89A; font-size: 11pt; padding: 12px;
                        background: rgba(85, 155, 115, 0.10);
                        border-radius: 8px; border: 2px solid rgba(100, 168, 130, 0.26);
                        margin-top: 8px; font-weight: 600; line-height: 1.55;
                    """)
                    self.detected_medium_label.setText(f"{_lbl}   {_ampel_c}{_badge}")
                    self.detected_medium_label.setToolTip(_tip_e)
                    if getattr(self, "prognose_widget", None) is not None:
                        _dec_int: int | None = None
                        try:
                            if isinstance(_era_decade, str) and _era_decade.endswith("er"):
                                _dec_int = int(_era_decade[:-2])
                            elif isinstance(_era_decade, (int, float)):
                                _dec_int = int(_era_decade)
                        except (ValueError, TypeError):
                            pass
                        self.prognose_widget.update_era_genre(_dec_int, _era_genre or None)  # type: ignore[union-attr]

                    # -- Restorability banner --
                    self._restorability_score = _rest_score
                    if hasattr(self, "restorability_banner"):
                        self.restorability_banner.setText(_banner)
                        self.restorability_banner.setStyleSheet(_css_r)
                        self.restorability_banner.setToolTip(_tip_r)
                        self.restorability_banner.setVisible(True)
                    if _rest_r is not None and getattr(self, "prognose_widget", None) is not None:
                        self.prognose_widget.update_restorability(_rest_r)  # type: ignore[union-attr]

                    # -- Defects --
                    if hasattr(self, "defect_count_live_label"):
                        self.defect_count_live_label.setText(t("status.analyzing_short"))
                        self.defect_count_live_label.setVisible(True)
                    with contextlib.suppress(Exception):
                        self._update_defects(_defects)
                    self._defect_scan_scores = _defects
                    if getattr(self, "prognose_widget", None) is not None:
                        with contextlib.suppress(Exception):
                            self.prognose_widget.update_defects(_defects)  # type: ignore[union-attr]
                    self._apply_mode_recommendation_visuals()

                    # -- Gate signals --
                    # era_genre: always; defect_scan: only when batch is not running
                    _try_signal_preanalysis_done("era_genre")
                    _batch_running = bool(self.batch_thread and self.batch_thread.isRunning())
                    if not _batch_running:
                        _try_signal_preanalysis_done("defect_scan")

                self.dispatch_to_gui(_update_all)

            threading.Thread(target=_pre_analysis_bg, daemon=True).start()
            # ── Ende Unified Pre-Analysis-Hintergrund ─────────────────────

            # ── Synchronisations-Timeout (15 s) ───────────────────────────
            # Fallback: Falls Ära/Genre-Analyse nach 15 s kein Ergebnis liefert
            # (z. B. Bridge nicht verfügbar, ClassifierException), werden die
            # Magic Buttons dennoch freigegeben — kein ewiges Warten für den Nutzer.
            def _preanalysis_timeout() -> None:
                # Primary guard: ignore if a newer load of the same file has started.
                if getattr(self, "_file_load_token", 0) != _snap_token:
                    return
                if str(getattr(self, "current_file_path", "")) != _cfk:
                    return  # stale — user opened a different file
                if bool(self.batch_thread and self.batch_thread.isRunning()):
                    return  # processing already running, buttons managed elsewhere
                # Mark era/genre timeout elapsed so the next completed signal can finalize.
                # Do NOT call _finalize_preanalysis() here directly: if the defect scan is
                # still running (common for files > ~60 s), the buttons would be enabled
                # before defects are displayed.  Instead we set the flag and let
                # _try_signal_preanalysis_done("defect_scan") pick it up when the scan
                # finishes.  If defect scan is already done, finalize immediately.
                self._preanalysis_timeout_fired = True
                if "defect_scan" in self._preanalysis_flags:
                    _finalize_preanalysis()
                # else: wait — defect_scan will call _finalize_preanalysis via
                # _try_signal_preanalysis_done once it completes.

            def _preanalysis_hard_timeout() -> None:
                """Absolute fallback (180 s): never bypass defect-scan gate."""
                if getattr(self, "_file_load_token", 0) != _snap_token:
                    return
                if str(getattr(self, "current_file_path", "")) != _cfk:
                    return
                if bool(self.batch_thread and self.batch_thread.isRunning()):
                    return
                self._preanalysis_timeout_fired = True
                if "defect_scan" in self._preanalysis_flags:
                    _finalize_preanalysis()
                else:
                    # Keep waiting for defect scan to avoid "analysis completed"
                    # while detail cards still show analyzing placeholders.
                    logger.info(
                        "Pre-analysis hard-timeout reached, waiting for defect_scan before finalization: file=%s",
                        _cfk,
                    )

            QTimer.singleShot(15_000, _preanalysis_timeout)  # era/genre soft timeout
            QTimer.singleShot(180_000, _preanalysis_hard_timeout)  # absolute fallback

        except Exception as e:
            # Fehlerfall: Buttons sofort wieder freischalten (Defektanalyse startet nicht)
            for _btn_name in ("btn_magic_restoration", "btn_magic_studio"):
                if hasattr(self, _btn_name):
                    _btn = getattr(self, _btn_name)
                    _btn.setEnabled(True)
                    _btn.update()
            if hasattr(self, "progress_bar"):
                self.progress_bar.setRange(0, 10000)
                self.progress_bar.setValue(0)
                self.progress_bar.setVisible(False)
            self.detected_medium_label.setText(t("status.load_error_short", error=str(e)[:80]))
            self.detected_medium_label.setStyleSheet("""
                color: #B87A7A; font-size: 11pt; padding: 12px;
                background: rgba(148, 82, 82, 0.10);
                border-radius: 8px; border: 2px solid rgba(152, 88, 88, 0.26);
            """)
        self.title_bar.set_status(t("status.file_loaded"), "#82B89A")
        # ── Ende _on_file_loaded ───────────────────────────────────────────

    def _auto_preview_restored(self) -> None:
        """Auto-play first 5 s of restored audio shortly after completion (Feature 8)."""
        if getattr(self, "_rest_audio", None) is None:
            return
        if not _SD_AVAILABLE:
            return
        _already = hasattr(self, "_play_thread") and self._play_thread is not None and self._play_thread.is_alive()
        if _already:
            return
        _ra = self._rest_audio
        assert _ra is not None  # guarded by check above
        _preview = np.ascontiguousarray(_ra[: min(len(_ra), 5 * 48000)], dtype=np.float32)
        if _preview.size > 0:
            self._play_audio(_preview, 48000)

    def _on_waveform_seek_request(self, frac: float) -> None:
        """Seek playback to clicked waveform position (0.0–1.0 of current source)."""
        frac = max(0.0, min(1.0, float(frac)))

        # ── Streaming-Player: gapless seek (kein stop/restart) ───────────────
        _sp = self._streaming_player
        if _sp is not None and _sp.available and _sp.is_playing:
            if hasattr(self, "waveform_widget"):
                self.waveform_widget.set_playhead_position(frac)
            _sp.seek(frac)
            _dur = _sp.duration_seconds
            if _dur > 0 and hasattr(self, "_playback_time_label"):
                _t = int(frac * _dur)
                _m, _s = divmod(_t, 60)
                _dm, _ds = divmod(int(_dur), 60)
                self._playback_time_label.setText(f"{_m}:{_s:02d} / {_dm}:{_ds:02d}")
            return

        # ── Legacy: position update + restart ────────────────────────────────
        _dur = float(getattr(self, "_playback_audio_duration", 0.0) or 0.0)
        if _dur > 0 and hasattr(self, "_playback_time_label"):
            _t = int(frac * _dur)
            _m, _s = divmod(_t, 60)
            _dm, _ds = divmod(int(_dur), 60)
            self._playback_time_label.setText(f"{_m}:{_s:02d} / {_dm}:{_ds:02d}")

        _is_playing = bool(self._play_thread is not None and self._play_thread.is_alive())
        if not _is_playing:
            return

        if hasattr(self, "waveform_widget"):
            self.waveform_widget.set_playhead_position(frac)

        _src = getattr(self, "_playback_source_audio", None)
        _src_sr = int(getattr(self, "_playback_source_sr", 0) or 0)
        if _src is None or _src_sr <= 0:
            return

        # Restart playback at requested absolute position in current source.
        self._play_audio(_src, _src_sr, start_pos_frac=frac)

    def _stop_sd_playback_locked(self) -> None:
        """Stop active sd.play() stream and signal polling thread (lock must be held)."""
        self._sd_stream = None
        _stop_evt = getattr(self, "_playback_stop_evt", None)
        if _stop_evt is not None:
            try:
                _stop_evt.set()
            except Exception:
                logger.debug("Playback: stop-event konnte nicht gesetzt werden", exc_info=True)
        # sd.stop() terminates the active sd.play() stream immediately
        try:
            if _sd is not None:
                _sd.stop()
        except Exception:
            logger.debug("Playback: _sd.stop() fehlgeschlagen", exc_info=True)

    def _play_audio(
        self,
        audio: np.ndarray,
        sr: int,
        start_pos_frac: float = 0.0,
        *,
        loudness_match_ref: np.ndarray | None = None,
    ):
        """Audiodaten unterbrechungsfrei abspielen (gapless source-switch via StreamingAudioPlayer)."""
        if loudness_match_ref is not None:
            audio, _ab_gain_db = _match_playback_loudness_to_reference(audio, loudness_match_ref)
            self._ab_loudness_match_gain_db = float(_ab_gain_db)
        else:
            self._ab_loudness_match_gain_db = 0.0
        # ── Streaming-Player-Pfad (bevorzugt — gapless, kein stop/restart) ───
        _sp = self._streaming_player
        if _sp is not None and _sp.available:
            # Pass raw audio reference — StreamingAudioPlayer._prepare()
            # handles normalisation/resampling internally with id()-based
            # cache.  Creating a copy here would kill the cache (new id()
            # on every call → full re-normalise + resample → GUI freeze +
            # GIL contention → audible stuttering under ML load).
            if audio is None or (hasattr(audio, "size") and audio.size == 0):
                if hasattr(self, "status_text"):
                    self._apply_status_text_style("error")
                    self.status_text.setText(
                        "⚠ Wiedergabe nicht möglich: Die Audiodatei enthält keine abspielbaren Samples."
                    )
                if hasattr(self, "title_bar"):
                    self.title_bar.set_status("Wiedergabe-Fehler", "#B87A7A")
                return

            # Persist source for click-to-seek (raw ref — stable id())
            self._playback_source_audio = audio
            self._playback_source_sr = int(sr)

            ok = _sp.play(
                audio,
                int(sr),
                start_frac=float(start_pos_frac),
                label="",
                on_finished=self._on_streaming_playback_finished,
            )
            if ok:
                if hasattr(self, "btn_stop_playback"):
                    self.btn_stop_playback.setEnabled(True)

                # ── Playhead-Timer ────────────────────────────────────────────────
                self._playback_audio_duration = _sp.duration_seconds
                self._last_playhead_pos = -1.0
                self._ensure_playhead_timer().start(120)
                return
            # StreamingAudioPlayer.play() failed → fall through to sd.play() fallback
            logger.warning("StreamingAudioPlayer.play() returned False — falling back to sd.play()")

        # ── Legacy-Fallback: sd.play() (nicht gapless) ───────────────────────
        if not _SD_AVAILABLE:
            QMessageBox.information(self, t("dialog.player_title"), t("dialog.player_body"))
            return
        prepared_audio = np.ascontiguousarray(_normalize_audio(audio), dtype=np.float32)
        if prepared_audio.size == 0:
            if hasattr(self, "status_text"):
                self._apply_status_text_style("error")
                self.status_text.setText(
                    "⚠ Wiedergabe nicht möglich: Die Audiodatei enthält keine abspielbaren Samples."
                )
            if hasattr(self, "title_bar"):
                self.title_bar.set_status("Wiedergabe-Fehler", "#B87A7A")
            return

        # Persist source so click-to-seek can restart from the same content.
        self._playback_source_audio = prepared_audio
        self._playback_source_sr = int(sr)

        # Thread-sichere Wiedergabe: Lock verhindert Race-Condition bei stop/play/wait
        if not hasattr(self, "_sd_lock"):
            self._sd_lock = threading.Lock()

        # Laufende Wiedergabe stoppen (geschützt)
        try:
            with self._sd_lock:
                self._stop_sd_playback_locked()
        except Exception as exc:
            logger.warning("A/B playback stop failed: %s", exc)

        def _play():
            try:
                data = prepared_audio
                if data.max() > 1.0 or data.min() < -1.0:
                    data = data / (np.abs(data).max() + 1e-9)
                play_sr = int(sr)

                _cache: PlaybackDeviceCacheEntry | None = getattr(self, "_playback_device_cache", None)
                _cache_hit = False
                if isinstance(_cache, tuple) and len(_cache) >= 4:
                    _cache_items = list(_cache)
                    _cache_source_id = _cache_items[0]
                    _cache_source_sr = _cache_items[1]
                    _cached_play_sr = _cache_items[2]
                    _cached_data = _cache_items[3]
                    if _cache_source_id == id(prepared_audio) and _cache_source_sr == sr:
                        data = np.ascontiguousarray(_cached_data, dtype=np.float32)
                        play_sr = int(_cached_play_sr)
                        _cache_hit = True
                if not _cache_hit:
                    try:
                        if _sd is not None:
                            _dev = _sd.query_devices(kind="output")
                            _dev_sr = (
                                int(round(float(_dev.get("default_samplerate", 0.0)))) if isinstance(_dev, dict) else 0
                            )
                            if _dev_sr > 0 and abs(_dev_sr - play_sr) >= 2000:
                                _rs = _resample_audio_poly(data, play_sr, _dev_sr, axis=0)
                                data = np.ascontiguousarray(_rs, dtype=np.float32)
                                play_sr = _dev_sr
                            if getattr(self, "_playback_warmup_token", -1) >= 0:
                                self._playback_device_cache = (id(prepared_audio), sr, play_sr, data)
                    except Exception as exc:
                        logger.debug("A/B playback device-rate adaption skipped: %s", exc)

                if data.ndim == 1:
                    data2 = data.reshape(-1, 1)
                else:
                    data2 = data
                data2 = np.ascontiguousarray(data2, dtype=np.float32)
                n_samples = int(data2.shape[0])
                _start_frac = max(0.0, min(1.0, float(start_pos_frac)))
                _start_idx = int(_start_frac * n_samples)
                data_to_play = data2[_start_idx:]

                finished_evt = threading.Event()
                self._playback_stop_evt = finished_evt
                self._sd_stream = None

                with self._sd_lock:
                    if _sd is None:
                        return
                    _sd.play(data_to_play, samplerate=play_sr, blocking=False, latency="high")

                while not finished_evt.is_set():
                    try:
                        _active = _sd is not None and _sd.get_stream().active
                    except Exception:
                        _active = False
                    if not _active:
                        break
                    time.sleep(0.05)

                finished_evt.set()
            except Exception as exc:
                _stopped_intentionally = bool(
                    getattr(self, "_playback_stop_evt", None) and self._playback_stop_evt.is_set()
                )
                if _stopped_intentionally:
                    return
                logger.warning("A/B playback failed: %s", exc)

                def _notify_playback_error(_exc: Exception = exc) -> None:
                    err = str(_exc)[:140]
                    if hasattr(self, "status_text"):
                        self._apply_status_text_style("error")
                        self.status_text.setText(
                            f"⚠ Wiedergabe fehlgeschlagen: {err}. Hinweis: Audio-Ausgabegerät prüfen."
                        )
                    if hasattr(self, "title_bar"):
                        self.title_bar.set_status("Wiedergabe-Fehler", "#B87A7A")

                self._dispatch_to_gui(_notify_playback_error)
            finally:
                try:
                    with self._sd_lock:
                        if _sd is not None:
                            try:
                                _sd.stop()
                            except Exception:
                                logger.debug("Playback-Thread: _sd.stop() im finally fehlgeschlagen", exc_info=True)
                        self._sd_stream = None
                except Exception:
                    logger.debug("Playback-Thread: Finally-Cleanup mit _sd_lock fehlgeschlagen", exc_info=True)
                self._playback_stop_evt = None

        self._play_thread = threading.Thread(target=_play, daemon=True)
        self._play_thread.start()
        if hasattr(self, "btn_stop_playback"):
            self.btn_stop_playback.setEnabled(True)

        # ── Playhead-Timer (läuft im Hauptthread) ────────────────────────────
        self._playback_start_time = time.monotonic() - max(0.0, min(1.0, float(start_pos_frac))) * (
            len(prepared_audio) / max(1, sr)
        )
        self._playback_audio_duration = len(audio) / max(1, sr)
        self._last_playhead_pos = -1.0
        self._ensure_playhead_timer().start(120)

    def _ensure_playhead_timer(self):
        """Gibt a live playhead timer; __init__ sets the attribute to None zurück."""
        timer = getattr(self, "_playhead_timer", None)
        if timer is None:
            timer = QTimer(self)
            timer.timeout.connect(self._update_playhead)
            self._playhead_timer = timer
        return timer

    def _on_streaming_playback_finished(self) -> None:
        """Callback from StreamingAudioPlayer when source ends naturally.

        Runs in the PortAudio thread — dispatch UI updates to GUI thread.
        """
        self._dispatch_to_gui(self._on_playback_ended_gui)

    def _on_playback_ended_gui(self) -> None:
        """Setzt zurück: UI after playback ends (runs in GUI thread)."""
        timer = getattr(self, "_playhead_timer", None)
        if timer is not None:
            timer.stop()
        if hasattr(self, "waveform_widget"):
            self.waveform_widget.set_playhead_position(-1.0)
        if hasattr(self, "_playback_time_label"):
            self._playback_time_label.setText("– : – –")
        if hasattr(self, "btn_stop_playback"):
            self.btn_stop_playback.setEnabled(False)

    def _update_playhead(self) -> None:
        """120-ms-Timer-Slot: aktualisiert Playhead-Position und Zeitanzeige im Hauptthread."""
        # ── Streaming-Player: sample-genaue Position ─────────────────────────
        _sp = self._streaming_player
        if _sp is not None and _sp.available and _sp.is_playing:
            _pos = _sp.position_frac
            if _pos < 0.0:
                # Playback ended
                self._on_playback_ended_gui()
                return
            _elapsed = _sp.elapsed_seconds
            _dur = _sp.duration_seconds
        else:
            # ── Legacy-Fallback: time.monotonic()-basiert ─────────────────────
            _thread_alive = (
                hasattr(self, "_play_thread") and self._play_thread is not None and self._play_thread.is_alive()
            )
            if not _thread_alive:
                self._on_playback_ended_gui()
                return
            _elapsed = time.monotonic() - self._playback_start_time
            _dur = self._playback_audio_duration
            _pos = min(_elapsed / max(_dur, 1e-9), 1.0)
        # Avoid expensive full-waveform repaints for tiny cursor movements.
        _last_pos = float(getattr(self, "_last_playhead_pos", -1.0))
        if _last_pos >= 0.0 and abs(_pos - _last_pos) < 0.004:
            if hasattr(self, "_playback_time_label") and _dur > 0:
                _em, _es = divmod(int(_elapsed), 60)
                _dm, _ds = divmod(int(_dur), 60)
                self._playback_time_label.setText(f"{_em}:{_es:02d} / {_dm}:{_ds:02d}")
            return
        self._last_playhead_pos = _pos
        if hasattr(self, "waveform_widget"):
            self.waveform_widget.set_playhead_position(_pos)
        if hasattr(self, "_playback_time_label") and _dur > 0:
            _em, _es = divmod(int(_elapsed), 60)
            _dm, _ds = divmod(int(_dur), 60)
            self._playback_time_label.setText(f"{_em}:{_es:02d} / {_dm}:{_ds:02d}")

    def _play_delta(self) -> None:
        """§14.9: Differenzsignal berechnen und abspielen."""
        if self._orig_audio is None or self._rest_audio is None:
            return
        try:
            from backend.api.bridge import get_ab_delta as _abd

            compute_ab_delta = _abd()
            delta = compute_ab_delta(self._orig_audio, self._rest_audio)
            self._play_audio(delta, self._orig_sr or 48000)
        except Exception as e:
            logger.warning("Delta-Berechnung fehlgeschlagen: %s", e)

    def _play_restored_or_preview(self) -> None:
        """Spielt restauriertes Audio oder — während laufender Restaurierung — den
        aktuellen Zwischenstand (Snapshot der zuletzt abgeschlossenen Phase).

        Die Restaurierung läuft unverändert weiter; Playback und Pipeline laufen
        auf getrennten Threads.
        """
        if self._rest_audio is not None:
            self._play_audio(self._rest_audio, self._rest_sr, loudness_match_ref=self._orig_audio)
            return
        _preview = getattr(self, "_live_preview_audio", None)
        _preview_sr = int(getattr(self, "_live_preview_sr", 48000))
        if _preview is not None:
            _safe_preview = _guard_preview_short_term_loudness(_preview, self._orig_audio, _preview_sr)
            self._play_audio(_safe_preview, _preview_sr)

    def _audio_output_ready(self) -> tuple[bool, str]:
        """Prüft, ob ein echtes Ausgabegerät für die A/B-Wiedergabe verfügbar ist."""
        _sp = getattr(self, "_streaming_player", None)
        if _sp is not None:
            try:
                if _sp.available:
                    return True, ""
            except Exception:
                logger.debug("A/B-Player: Streaming-Ausgabegerät konnte nicht geprüft werden", exc_info=True)
            return False, "Kein Audio-Ausgabegerät gefunden."
        if not _SD_AVAILABLE or _sd is None:
            return False, "Audio-Wiedergabe ist auf diesem System nicht verfügbar."
        try:
            _dev = _sd.query_devices(kind="output")
            if isinstance(_dev, dict):
                _channels = int(_dev.get("max_output_channels", 0) or 0)
                _rate = float(_dev.get("default_samplerate", 0.0) or 0.0)
                if _channels > 0 and _rate > 0.0:
                    return True, ""
        except Exception:
            logger.debug("A/B-Player: sounddevice-Ausgabegerät konnte nicht geprüft werden", exc_info=True)
        return False, "Kein Audio-Ausgabegerät gefunden."

    @staticmethod
    def _set_button_enabled_with_reason(button, enabled: bool, enabled_tooltip: str, disabled_reason: str) -> None:
        """Setzt Button-Zustand mit verständlichem Grund für deaktivierte Bedienung."""
        if button is None:
            return
        button.setEnabled(bool(enabled))
        button.setToolTip(str(enabled_tooltip or "") if enabled else f"Nicht verfügbar: {disabled_reason}")

    def _update_ab_player_state(self):
        """A/B-Player Buttons je nach verfügbaren Audiodaten aktivieren."""
        _output_ready, _output_reason = self._audio_output_ready()
        if hasattr(self, "btn_play_original"):
            _has_orig = self._orig_audio is not None
            _reason = "Original-Audio ist noch nicht geladen." if not _has_orig else _output_reason
            self._set_button_enabled_with_reason(
                self.btn_play_original,
                _has_orig and _output_ready,
                "Originalaufnahme anhören.",
                _reason,
            )
        if hasattr(self, "btn_play_restored"):
            _processing = bool(getattr(self, "batch_thread", None) and self.batch_thread.isRunning())
            _has_preview = getattr(self, "_live_preview_audio", None) is not None
            _has_rest = self._rest_audio is not None
            # Live-Label während Restaurierung
            if _processing and _has_preview and not _has_rest:
                self.btn_play_restored.setText("🎧  Zwischenstand hören")
                _tip = (
                    "Zwischenstand der Restaurierung anhören (Snapshot der letzten Phase).\n"
                    "Die Restaurierung läuft im Hintergrund weiter."
                )
                _reason = _output_reason if not _output_ready else "Noch kein Zwischenstand verfügbar."
                self._set_button_enabled_with_reason(
                    self.btn_play_restored,
                    _output_ready,
                    _tip,
                    _reason,
                )
            else:
                self.btn_play_restored.setText(f"▶  {t('action.listen_restored')}")
                _reason = "Restaurierter Export liegt noch nicht vor." if not _has_rest else _output_reason
                self._set_button_enabled_with_reason(
                    self.btn_play_restored,
                    _has_rest and _output_ready,
                    "Restaurierte Fassung anhören.",
                    _reason,
                )
        # A/B-Sync-Loop erfordert beide Versionen
        if hasattr(self, "btn_ab_sync"):
            _both = self._orig_audio is not None and self._rest_audio is not None
            _sync_ready = _both and _output_ready
            _sync_reason = "Original und restaurierter Export werden beide benötigt." if not _both else _output_reason
            self._set_button_enabled_with_reason(
                self.btn_ab_sync,
                _sync_ready,
                "Synchronisierten A/B-Loop starten; A/B wechseln bei gleicher Position.",
                _sync_reason,
            )
            if not _sync_ready and getattr(self.btn_ab_sync, "isChecked", lambda: False)():
                self.btn_ab_sync.setChecked(False)
                if hasattr(self, "_ab_source_label"):
                    self._ab_source_label.setVisible(False)
        # Stop-Button nur aktivierbar wenn Wiedergabe läuft — Grundzustand: deaktiviert
        if hasattr(self, "btn_stop_playback"):
            _sp = self._streaming_player
            if _sp is not None and _sp.available:
                _playing = _sp.is_playing
            else:
                _playing = (
                    hasattr(self, "_play_thread") and self._play_thread is not None and self._play_thread.is_alive()
                )
            self._set_button_enabled_with_reason(
                self.btn_stop_playback,
                _playing,
                t("tooltip.stop_playback"),
                "Keine Wiedergabe aktiv.",
            )
        if hasattr(self, "_ab_source_label"):
            _has_any_audio = (
                self._orig_audio is not None
                or self._rest_audio is not None
                or getattr(self, "_live_preview_audio", None) is not None
            )
            _loop_checked = bool(
                hasattr(self, "btn_ab_sync") and getattr(self.btn_ab_sync, "isChecked", lambda: False)()
            )
            if _has_any_audio and not _output_ready and not _loop_checked:
                self._ab_source_label.setText(f"Audio-Ausgabe nicht verfügbar · {_output_reason}")
                self._ab_source_label.setStyleSheet(
                    f"color: rgba(208,139,139,0.92); font-size: {self._pt(8.5):.1f}pt; "
                    "font-weight: bold; padding: 0 4px;"
                )
                self._ab_source_label.setVisible(True)
            elif not _loop_checked:
                self._ab_source_label.setVisible(False)

    def _ab_sync_toggle(self) -> None:
        """A/B-Sync-Loop starten oder stoppen (v9.10.111).

        Beim Start: aktuelle Playhead-Position (oder 0.0) als Loop-Startpunkt
        speichern, Original abspielen. Beim Stopp: Wiedergabe beenden, State
        zurücksetzen. Während des Loops wechseln A/B-Shortcuts die Quelle bei
        gleicher Startposition.
        """
        if not getattr(self.btn_ab_sync, "isChecked", lambda: False)():
            # Loop deaktiviert — Wiedergabe stoppen, State zurücksetzen
            self._stop_song_playback_only()
            if hasattr(self, "_ab_source_label"):
                self._ab_source_label.setVisible(False)
            return

        # Loop aktiviert — Startposition bestimmen (aktueller Playhead oder 0)
        # Streaming-Player liefert sample-genaue Position (kein 120ms-Timer-Drift)
        _sp = self._streaming_player
        if _sp is not None and _sp.available and _sp.is_playing:
            _pos = _sp.position_frac
        else:
            _pos = float(getattr(self, "_last_playhead_pos", -1.0))
        if _pos < 0.0 or _pos >= 1.0:
            _pos = 0.0
        self._ab_loop_start_frac = _pos
        self._ab_loop_source = "original"
        self._ab_play_loop_source()

    def _ab_play_loop_source(self) -> None:
        """Interne Hilfsmethode: spielt die aktive A/B-Loop-Quelle ab Startposition."""
        _loop_active = hasattr(self, "btn_ab_sync") and getattr(self.btn_ab_sync, "isChecked", lambda: False)()
        if not _loop_active:
            return
        _src = getattr(self, "_ab_loop_source", "original")
        _frac = float(getattr(self, "_ab_loop_start_frac", 0.0))
        if _src == "restored" and self._rest_audio is not None:
            self._play_audio(self._rest_audio, self._rest_sr, start_pos_frac=_frac, loudness_match_ref=self._orig_audio)
            _gain_db = float(getattr(self, "_ab_loudness_match_gain_db", 0.0) or 0.0)
            _match_txt = f" · Pegelmatch {_gain_db:+.1f} dB" if abs(_gain_db) >= 0.1 else " · Pegelmatch aktiv"
            _lbl = f"Quelle: ✦ Restauriert{_match_txt}"
            _col = "rgba(80,220,100,0.85)"
        else:
            if self._orig_audio is not None:
                self._play_audio(self._orig_audio, self._orig_sr, start_pos_frac=_frac)
            _lbl = "Quelle: ▶ Original"
            _col = "rgba(100,150,255,0.85)"
        if hasattr(self, "_ab_source_label"):
            self._ab_source_label.setText(_lbl)
            self._ab_source_label.setStyleSheet(
                f"color: {_col}; font-size: {self._pt(8.5):.1f}pt; font-weight: bold; padding: 0 4px;"
            )
            self._ab_source_label.setVisible(True)

    def _ab_switch_source(self, source: str) -> None:
        """Wechselt die A/B-Loop-Quelle bei laufendem Loop (v9.10.111).

        Speichert die aktuelle Playhead-Position als neuen Startpunkt, stoppt
        die Wiedergabe und startet die andere Quelle von derselben Position.
        Nur aktiv wenn A/B-Sync-Loop läuft.
        """
        _loop_active = hasattr(self, "btn_ab_sync") and getattr(self.btn_ab_sync, "isChecked", lambda: False)()
        if not _loop_active:
            return
        # Aktuelle Playhead-Position als neuen Loop-Startpunkt übernehmen
        # Streaming-Player liefert sample-genaue Position (kein 120ms-Timer-Drift)
        _sp = self._streaming_player
        if _sp is not None and _sp.available and _sp.is_playing:
            _current_pos = _sp.position_frac
        else:
            _current_pos = float(getattr(self, "_last_playhead_pos", -1.0))
        if 0.0 <= _current_pos < 1.0:
            self._ab_loop_start_frac = _current_pos
        self._ab_loop_source = source
        self._ab_play_loop_source()

    def _dialog_options(self, *, directory_only: bool = False) -> QFileDialog.Options:
        """Erstellt QFileDialog options for the Qt fallback path.

        We force non-native Qt dialogs so Aurik styling is consistently applied
        across all platforms.
        """
        opts = QFileDialog.Options()
        opts |= QFileDialog.Option.DontUseNativeDialog
        if directory_only:
            opts |= QFileDialog.Option.ShowDirsOnly
        return opts

    def _pick_with_system_dialog(
        self,
        *,
        title: str,
        start_dir: str,
        multiple: bool = False,
        directory: bool = False,
        save: bool = False,
        default_filename: str = "",
    ) -> list[str]:
        """Use native OS system dialogs for file/directory selection.

        Priority:
          1. Linux: zenity (GTK) or kdialog (KDE) — avoids Qt frameless-window issues
          2. All platforms: tkinter native dialog (Win32 on Windows, Tk on Linux fallback)
          Returns an empty list if the user cancels or no dialog is available.
        """
        start = start_dir or str(Path.home())
        _audio_filter = "*.wav *.mp3 *.flac *.ogg *.aiff *.aif *.m4a *.wma *.aac"

        # ── 1. Linux: zenity (GTK native) ─────────────────────────────────
        if sys.platform.startswith("linux") and shutil.which("zenity"):
            cmd = ["zenity", "--file-selection", f"--title={title}"]
            if directory:
                cmd.append("--directory")
            elif save:
                cmd.append("--save")
                fn = start.rstrip("/") + "/" + (default_filename or "")
                cmd.append(f"--filename={fn}")
            else:
                if multiple:
                    cmd.extend(["--multiple", "--separator=\n"])
                cmd.append(f"--filename={start.rstrip('/')}/")
            try:
                proc = subprocess.run(cmd, capture_output=True, text=True, check=False)
                if proc.returncode == 0:
                    out = proc.stdout.strip()
                    if out:
                        return [p for p in out.splitlines() if p.strip()]
                    return []
            except Exception:
                logger.debug("Dateidialog (native): zenity-Aufruf fehlgeschlagen", exc_info=True)

        # ── 2. Linux: kdialog (KDE native) ────────────────────────────────
        if sys.platform.startswith("linux") and shutil.which("kdialog"):
            if save:
                fn = f"{start}/{default_filename}" if default_filename else start
                cmd = ["kdialog", "--getsavefilename", fn, "--title", title]
            elif directory:
                cmd = ["kdialog", "--getexistingdirectory", start, "--title", title]
            elif multiple:
                cmd = [
                    "kdialog",
                    "--getopenfilename",
                    start,
                    _audio_filter,
                    "--multiple",
                    "--separate-output",
                    "--title",
                    title,
                ]
            else:
                cmd = ["kdialog", "--getopenfilename", start, _audio_filter, "--title", title]
            try:
                proc = subprocess.run(cmd, capture_output=True, text=True, check=False)
                if proc.returncode == 0:
                    out = proc.stdout.strip()
                    if out:
                        return [p for p in out.splitlines() if p.strip()]
                    return []
            except Exception:
                logger.debug("Dateidialog (native): kdialog-Aufruf fehlgeschlagen", exc_info=True)

        # ── 3. Tkinter native dialog (Windows only) ─────────────────────────
        if not sys.platform.startswith("linux"):
            try:
                if _tk is None:
                    raise RuntimeError("tkinter nicht verfügbar")

                _root = _tk.Tk()
                _root.withdraw()
                _root.wm_attributes("-topmost", True)
                _audio_types = [
                    ("Audio-Dateien", _audio_filter.replace(" ", " ")),
                    ("Alle Dateien", "*"),
                ]
                try:
                    if directory:
                        path = _tk_filedialog.askdirectory(title=title, initialdir=start, mustexist=False, parent=_root)
                        return [path] if path else []
                    if save:
                        path = _tk_filedialog.asksaveasfilename(
                            title=title,
                            initialdir=start,
                            initialfile=default_filename,
                            filetypes=[("Alle Dateien", "*")],
                            parent=_root,
                        )
                        return [path] if path else []
                    if multiple:
                        paths = _tk_filedialog.askopenfilenames(
                            title=title,
                            initialdir=start,
                            filetypes=_audio_types,
                            parent=_root,
                        )
                        return list(paths) if paths else []
                    path = _tk_filedialog.askopenfilename(
                        title=title,
                        initialdir=start,
                        filetypes=_audio_types,
                        parent=_root,
                    )
                    return [path] if path else []
                finally:
                    with contextlib.suppress(Exception):
                        _root.destroy()
            except Exception:
                logger.debug("Dateidialog (native): Tkinter-Fallback fehlgeschlagen", exc_info=True)

        return []

